import axios from "axios";
import Vue from "vue";

/**
 * 获取 PDF 文件的检查点数据
 * @param {String} id - PDF 文件的唯一 ID
 * @returns {Promise<Object>} 返回按页存储的检查点数据
 */

    export async function getCheckResults(selectedId,pageNumber,type) {
      try {
        const response = await axios.post(`${Vue.prototype.$apiUrl}/api/check_results`, {
          selectedId,pageNumber,type
    });
    // console.log(response,'call api check_results---->')
    // if (response.data.code === 200) {
    //   return response.data; // 返回 { code: 200, data: { "1": [...], "2": [...] } }
    if (response.data.code === 200) {
      const allData = response.data.data; // 전체 데이터
      const filteredData = {};

      // pageNumber에 따라 데이터 필터링
      const targetPage = pageNumber ; // pageNumber를 1부터 시작하도록 변환
      if (allData[targetPage]) {
        filteredData[targetPage] = allData[targetPage]; // 해당 페이지의 데이터만 필터링
      }

      return { code: 200, data: filteredData }; // 필터링된 데이터 반환
    } else {
      console.error("检查点数据获取失败:", response.data.message);
      return { code: response.data.code, data: {} };
    }
  } catch (error) {
    console.error("请求检查点数据失败:", error);
    return { code: 500, data: {} };
  }
}

// ✅ API: 启动/停止 自动检查
// ✅ API: 启动/停止 自动检查
export function startAutoCheck(data) {
  return axios.put(`${Vue.prototype.$apiUrl}/api/monitoring-status`, data);
}

export function checkAutoCheck() {
  return axios.get(`${Vue.prototype.$apiUrl}/api/monitoring-status`);
}

export function manualCheck(checkType, selectedId = null) {
  return axios.post("/api/manual-check", {
      checkType,
      checkId: checkType === "O" ? selectedId : "all",  // O = 单个文件, A = 全部
  }).then((res) => res.data);
}
