import axios from "axios";
import Vue from "vue";

// ✅ 获取 Proxy 账户信息
export function getProxyAccount() {
  return axios.get(`${Vue.prototype.$apiUrl}/api/proxyinfo`).then(response => response.data);
}

// ✅ update Proxy 账户信息
export function saveProxyAccount(username, password) {
  return axios
    .put(`${Vue.prototype.$apiUrl}/api/proxyinfo`, { username, password })
    .then(response => response.data);
}

//get userinfo
export function getServerAccount() {
    return axios.get(`${Vue.prototype.$apiUrl}/api/users`).then((res) => res.data);
  }
  //create
export function saveServerAccount(username, password) {
    return axios.post(`${Vue.prototype.$apiUrl}/api/users`, { username, password }).then((res) => res.data);
  }

// ✅ 获取路径信息
export function getPaths() {
    return axios.get(`${Vue.prototype.$apiUrl}/api/getaths`).then((res) => res.data);
  }
  
  // ✅ 保存路径信息
  export function savePaths(newPaths) {
    return axios.post(`${Vue.prototype.$apiUrl}/api/saveaths`, newPaths).then((res) => res.data);
  }

 