<template>
  <!-- v-loading  -->
  <el-dialog v-loading.fullscreen.lock="isLoading" element-loading-text="ファイルをアップロード中..."
    element-loading-spinner="el-icon-loading" element-loading-background="rgba(255, 255, 255, 0)" title="手動アップロード"
    :visible.sync="visible" width="60%" @close="handleClose" @open="handleOpen">
    <!-- ✅ 选择文件类型 -->
    <div>
      <h3>アップロードするファイルを選択</h3>
      <el-select v-model="selectedFileType" placeholder="ファイル種類を選択" class="full-width" @change="resetSelections">
        <el-option label="参照ファイル" value="参照ファイル"></el-option>
        <el-option label="チェック対象ファイル" value="チェック対象ファイル"></el-option>
      </el-select>
    </div>

    <!-- ✅ 选择子类别（针对 参照ファイル） -->
    <div v-if="selectedFileType === '参照ファイル'">
      <h3>ファイルの種類を選択</h3>
      <el-select v-model="selectedReferenceCategory" placeholder="ファイルの種類" class="full-width">
        <!-- <el-option label="10銘柄解説一覧表" value="10銘柄解説一覧表"></el-option> -->
        <el-option label="レポートデータ" value="レポートデータ"></el-option>
        <el-option v-if="fundType === '私募'" label="紐付け管理表" value="紐付け管理表"></el-option>
      </el-select>
    </div>

    <!-- ✅ 选择子类别（针对 チェック対象ファイル） -->
    <div v-if="selectedFileType === 'チェック対象ファイル'">
      <h3>ファイルの種類を選択</h3>
      <el-select v-model="selectedCategory" placeholder="ファイルの種類" class="full-width" @change="resetMethod">
        <el-option label="共通コメントファイル" value="共通コメントファイル"></el-option>
        <el-option label="個別コメントファイル" value="個別コメントファイル"></el-option>
      </el-select>
    </div>

    <!-- ✅ 选择上传方式 -->
    <div v-if="selectedFileType && (selectedCategory || selectedReferenceCategory)">
      <h3>アップロード方法を選択</h3>
      <el-select v-model="selectedMethod" placeholder="アップロード方法" class="full-width">
        <el-option label="指定パス" value="path"></el-option>
        <el-option label="指定ファイル" value="file"></el-option>
      </el-select>
    </div>

    <!-- ✅ 指定パス -->
    <div v-if="selectedMethod === 'path'" class="path-popup-container">
      <h3>パスを入力してください</h3>
      <div class="input-row">
        <label for="path" class="input-label nowrap-label">パス：</label>
        <el-input id="path" v-model="filePath" placeholder="ファイルパスを入力してください。" clearable readonly></el-input>
        <el-button type="primary" @click="openFileSelector">フォルダ選択</el-button>
        <input type="file" webkitdirectory directory ref="fileInput" @change="handleFileSelection"
          style="display: none" />
      </div>
      <div class="file-list">
        <div class="file-count">検出されたファイル数：{{ fileList.length }}個</div>
        <table>
          <tbody>
            <tr v-for="(file, index) in fileList" :key="index">
              <td><a href="#" :class="{ 'red-text': file.isError }">{{ file.name }}</a></td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- ✅ 指定ファイル -->
    <div v-if="selectedMethod === 'file'" class="file-popup-container">
      <h3>ファイルをアップロードしてください</h3>
      <div class="upload-section">
        <el-upload action="" drag multiple :auto-upload="false" :on-change="handleFileChange">
          <i class="el-icon-upload"></i>
          <div class="el-upload__text">ここにファイルをドラッグ＆ドロップ</div>
        </el-upload>
      </div>
    </div>

    <span slot="footer" class="dialog-footer">
      <el-button type="primary" @click="handleConfirm" :disabled="isLoading">確認</el-button>
      <el-button @click="handleClose">閉じる</el-button>
    </span>
  </el-dialog>
</template>

<script>
import Vue from "vue";

export default {
  name: "PathPopup",
  props: {
    visible: {
      type: Boolean,
      required: true,
    },
    selectedFolder: {  // 추가: 선택된 폴더 정보
      type: String,
      default: ''
    }
  },
  data() {
    return {
      isLoading: false, // 로딩 상태 추가
      selectedFileType: "",
      selectedReferenceCategory: "",
      selectedCategory: "",
      selectedMethod: "",
      filePath: "",
      fileList: [],
      fundType: this.$route.query.fundType || "公募",
      currentFolder: "", // 현재 선택된 폴더를 저장할 변수 추가
    };
  },
  watch: {
    selectedFileType() {
      // 파일 타입이 변경되면 카테고리 초기화
      this.selectedCategory = "";
      this.selectedReferenceCategory = "";
    },
    selectedCategory(newCategory) {
      if (newCategory === "共通コメントファイル") {
        this.currentFolder = "📂 共通コメントファイル";
      } else if (newCategory === "個別コメントファイル") {
        this.currentFolder = "📂 個別コメントファイル";
      }
    },
    selectedReferenceCategory(newCategory) {
      if (newCategory === "10銘柄解説一覧表") {
        this.currentFolder = "📂 10銘柄解説一覧表";
      } else {
        this.currentFolder = "📂 レポートデータ";
      }
    }
  },
  methods: {
    // ✅ transformToMenuData 함수 추가
    transformToMenuData(apiData) {
      const menuData = {
        公募: [
          {
            id: "reference",
            name: "📁 参照ファイル",
            children: [
              {
                id: "report_data",
                name: "📂 レポートデータ",
                children: [], // to be populated
              },
              {
                id: "mingbing_data",
                name: "📂 10銘柄解説一覧表",
                children: [], // to be populated
              },
            ],
          },
          {
            id: "checked_files",
            name: "📁 チェック対象ファイル",
            children: [
              {
                id: "individual_comments",
                name: "📂 共通コメントファイル",
                children: [], // to be populated
              },
              {
                id: "kobetsucomment",
                name: "📂 個別コメントファイル",
                children: [], // to be populated
              },
            ],
          },
        ],
        私募: [
          {
            id: "reference",
            name: "📁 参照ファイル",
            children: [
              {
                id: "report_data",
                name: "📂 レポートデータ",
                children: [], // to be populated
              },
              {
                id: "mingbing_data",
                name: "📂 10銘柄解説一覧表",
                children: [], // to be populated
              },
            ],
          },
          {
            id: "checked_files",
            name: "📁 チェック対象ファイル",
            children: [
              {
                id: "individual_comments",
                name: "📂 共通コメントファイル",
                children: [], // to be populated
              },
              {
                id: "kobetsucomment",
                name: "📂 個別コメントファイル",
                children: [], // to be populated
              },
            ],
          },
        ],
      };

      // ✅ 公募 또는 私募 판단
      const category = apiData.code === 200 ? "公募" : "私募"; // Replace with appropriate condition to check category


      // ✅ reference 데이터 추가
      const referenceData = apiData.corrections.map((item, index) => ({
        id: index.toString(),
        name: item.fileName,
        icon: "📄",
        file: item.fileName,
        pdfPath: item.link,
      }));

      const mingbingData = referenceData; // Reusing the same data for mingbing_data, adjust if needed

      // ✅ reference 데이터 추가
      menuData[category][0].children[0].children_report = referenceData; // report_data
      menuData[category][0].children[1].children = mingbingData; // mingbing_data

      // ✅ checked_files 데이터 추가
      const individualComments = apiData.corrections.map((item, index) => ({
        id: (index + 6).toString(),
        name: `修正コメント - ${item.fileName}`,
        icon: item.result.corrections.length > 0 ? "⚠️" : "✅", // ⚠️---check done,checkerror  ❌ ---check fail  ✅;--check done ,none error
        file: item.fileName,
        status: item.status,
        readStatus: item.readStatus,
        pdfPath: item.link,
      }));

      const kobetsuComments = individualComments; // Reusing the same data for kobetsucomment, adjust if needed

      // ✅ checked_files 데이터 추가
      menuData[category][1].children[0].children = individualComments; // individual_comments
      menuData[category][1].children[1].children = kobetsuComments; // kobetsucomment

      return menuData;
    },
    split_text(text, maxLength) {
      const chunks = [];
      let startIndex = 0;
      while (startIndex < text.length) {
        const endIndex = startIndex + maxLength;
        chunks.push(text.slice(startIndex, endIndex));
        startIndex = endIndex;
      }
      return chunks;
    },

    resetSelections() {
      this.selectedCategory = "";
      this.selectedReferenceCategory = "";
      this.selectedMethod = "";
      this.fileList = [];
    },

    resetMethod() {
      this.selectedMethod = "";
      this.fileList = [];
    },

    openFileSelector() {
      this.$refs.fileInput.click();
    },

    handleFileSelection(event) {
      const files = Array.from(event.target.files);
      if (files.length === 0) return;

      // file path (예: ["parentFolder", "subFolder"])
      this.filePath = files[0].webkitRelativePath
        ? files[0].webkitRelativePath.split("/").slice(0, -1)
        : [];

      // Save file list
      this.fileList = files.map((file) => ({
        raw: file,
        name: file.name,
        relativePath: file.webkitRelativePath, // 相对路径保存
        isError: false,
      }));
    },

    handleFileChange(file, fileList) {
      this.fileList = fileList.map((f) => ({
        raw: f.raw,
        name: f.name,
        isError: false,
      }));
    },

    async handleConfirm() {
      if (!this.fileList.length) {
        this.$message.warning("アップロードするファイルがありません");
        return;
      }

      this.isLoading = true; // start loding
    // api async
    try {
        const targetCategory = this.selectedFileType === "参照ファイル"
          ? this.selectedReferenceCategory
          : this.selectedCategory;
        const menuLists = [];
        const uploadPromises = this.fileList.map(async (file) => {
          const formData = new FormData();
          formData.append('files', file.raw);
          formData.append('fundType', this.fundType === '私募' ? 'private' : 'public');
          formData.append('fileType', this.selectedFileType);
          formData.append('category', targetCategory);
          formData.append('uploadMethod', this.selectedMethod);
          formData.append('filePath', this.filePath);

          const uploadResponse = await fetch(`${Vue.prototype.$apiUrl}/api/check_upload`, {
            method: 'POST',
            body: formData
          });

          if (!uploadResponse.ok) {
            throw new Error(`サーバーエラー: ${uploadResponse.status} ${uploadResponse.statusText}`);
          }

          const uploadResult = await uploadResponse.json();
          if (!uploadResult.success) {
            throw new Error(uploadResult.error || 'ファイルの処理中にエラーが発生しました。');
          }
          return uploadResult;
        });
        
        const uploadResults = await Promise.all(uploadPromises);

        const gptPromises = uploadResults.map(async (uploadResult) => {
          const filename = uploadResult.file_name.match(/[^/\\]+$/)[0];
          // const fileExtension = filename.split('.').pop().toLowerCase();
          // const inputText = fileExtension === "xlsx" ? "test" : uploadResult.original_text; // XLSXは全体を渡さない

          const inputText = uploadResult.original_text;

          // 🧹 캐시 키에서 filename이 포함된 항목 모두 삭제
          for (let i = localStorage.length - 1; i >= 0; i--) {
            const key = localStorage.key(i);
            if (key && key.startsWith("gpt_cache_") && key.includes(filename)) {
              localStorage.removeItem(key);
              console.log(`🗑️ キャッシュ削除済み: ${key}`);
            }
          }

          const gptResponse = await fetch(`${Vue.prototype.$apiUrl}/api/write_upload_save`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              input: inputText,
              pdf_bytes: uploadResult.pdf_bytes || "",
              excel_bytes: uploadResult.excel_bytes || "",
              file_name: filename || "",
              fund_type: this.fundType === '私募' ? 'private' : 'public',
              upload_type: this.selectedFileType,
              subCategory_type: this.selectedReferenceCategory === "紐付け管理表" ? 'report' : 'megara',
              comment_type: this.selectedCategory,
              change_flag: "change"
            }),
          });

          if (!gptResponse.ok) {
            throw new Error(`GPT API エラー: ${gptResponse.status} ${gptResponse.statusText}`);
          }
          this.$emit('load_count');
          return await gptResponse.json();
        });

        const gptResults = await Promise.all(gptPromises);

        if (this.selectedFileType !== "参照ファイル" || this.selectedReferenceCategory !== "紐付け管理表"){

        try{
          for (const uploadResult of uploadResults) {
            if (uploadResult.file_name.toLowerCase().endsWith('.pdf')) continue;
            const excelName = uploadResult.file_name.match(/[^/\\]+$/)[0];
            const startTime = Date.now();
            while (Date.now() - startTime < 300000) {
              try{
                const checkResponse = await fetch(`${Vue.prototype.$apiUrl}/api/check_file`, {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({
                    file_name: excelName,
                    fund_type: this.fundType === '私募' ? 'private' : 'public',
                    comment_type: this.selectedCategory,
                    upload_type: this.selectedFileType
                  })
                });
                const result = await checkResponse.json();
                if (result.success) {
                  this.$emit('loaded');
                  break
                }
              } catch (error) {
                console.error("Status check error:", error);
              }
              await new Promise(resolve => setTimeout(resolve, 1000));
            }
          }
        } catch (error) {
          throw new Error(`文件验证失败: ${error.message}`);
        }

        menuLists.push(...gptResults.corrected_text || '');

        // ファイルがExcel形式の場合、ダウンロード処理を行う（最初の成功したアップロード結果を使用）
        // const firstExcelResult = uploadResults.find(res => res.file_name && res.file_name.endsWith(".xlsx"));
        // if (firstExcelResult) {
        //   const gptDownloadResponse = await fetch(`${Vue.prototype.$apiUrl}/api/opt_typo`, {
        //     method: 'POST',
        //     headers: { 'Content-Type': 'application/json' },
        //     body: JSON.stringify({
        //       input: firstExcelResult.combined_text, // ダウンロード指示
        //       pdf_bytes: firstExcelResult.pdf_bytes,
        //       excel_bytes: firstExcelResult.excel_bytes,
        //       file_name: firstExcelResult.file_name,
        //       fund_type: this.fundType === '私募' ? 'private' : 'public',
        //       original_text: firstExcelResult.original_text,
        //       upload_type: this.selectedFileType,
        //       comment_type: this.selectedCategory
        //     }),
        //   });
            
        //   if (gptDownloadResponse.status ==200) {
        //     const blob = await gptDownloadResponse.blob();
        //     const url = window.URL.createObjectURL(blob);
        //     const a = document.createElement('a');
        //     a.href = url;
        //     a.download = firstExcelResult.file_name;
        //     a.click();
        //     window.URL.revokeObjectURL(url);
        //   } else {
        //     console.error("Excelダウンロードエラー:", gptDownloadResponse);
        //     this.$message.error("Excelファイルのダウンロードに失敗しました。");
        //   }
        // }
      }
        this.$emit("update:visible", false);
        this.isLoading = false;
        this.$message.success(`ファイルのアップロードが完了しました。`);
        this.$emit("updateMenu");

        // ✨ 複数のファイルアップロード結果を親コンポーネントに通知
        uploadResults.forEach((uploadResult, index) => {
          this.$emit('fileUploaded', {
            id: uploadResult.file_name,
            fileName: uploadResult.file_name,
            uploadResult: uploadResult,
            folder: this.selectedCategory || this.selectedReferenceCategory,
            fundType: this.fundType,
            raw: this.fileList[index].raw,
            selectedFileType: this.selectedFileType,
            selectedReferenceCategory: this.selectedReferenceCategory,
            selectedCategory: this.selectedCategory,
          });
        });

      } catch (error) {
        console.error("アップロードエラー:", error);
        this.$message.error("アップロード中にエラーが発生しました");
      } finally {
        this.isLoading = false;
      }
    },

  
    handleOpen() {
      this.selectedFileType = "";
      this.selectedCategory = "";
      this.selectedReferenceCategory = "";
      this.selectedMethod = "";
      this.filePath = "";
      this.fileList = [];
    },

    handleClose() {
      this.$emit("update:visible", false);
    },
  },
};
</script>

<style scoped>
.el-loading-spinner .el-loading-text {
  color: #409EFF;
  font-size: 32px;
  font-weight: bold;
  margin-top: 10px;
}

.el-loading-spinner .path {
  stroke: #409EFF;
}

.el-loading-mask {
  z-index: 3000;
}

.full-width {
  width: 100%;
  margin-bottom: 10px;
}

/* ✅ 让 "パス：" 不换行 */
.nowrap-label {
  white-space: nowrap;
}

.path-popup-container,
.file-popup-container {
  padding: 15px;
  border: 1px solid #ddd;
  border-radius: 5px;
  background-color: #f9f9f9;
}

.input-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.file-list {
  margin-top: 10px;
}

.file-count {
  font-weight: bold;
}

.upload-section {
  text-align: center;
  margin-top: 20px;
}

.dialog-footer {
  display: flex;
  justify-content: space-between;
}
</style>