<template>
  <el-dialog title="10銘柄解説管理" :visible.sync="dialogVisible" width="60%" @close="handleClose">
    <div class="search-box">
      <!-- Fコード -->
      <el-select
        v-model="selectedCode"
        clearable
        filterable
        placeholder="Fコードを選択してください"
        :filter-method="filterOptions"
        :loading="loading"
        style="width: 30%;"
        @change="onFcodeChange"
      >
        <el-option v-for="item in deduplicatedOptions" :key="item.id" :label="item.fcode" :value="item.fcode" />
      </el-select>

      <!-- 決算月 -->
      <el-select
        v-model="selectedMonth"
        clearable
        placeholder="決算月を選択"
        style="width: 30%;"
        :disabled="!selectedCode"
        @change="onMonthChange"
      >
        <el-option v-for="month in availableMonths" :key="month" :label="month" :value="month" />
      </el-select>

      <!-- 組入銘柄 -->
      <el-select
        v-model="selectedStock"
        clearable
        placeholder="組入銘柄を選択"
        style="width: 30%;"
        :disabled="!selectedCode"
        @change="onStockChange"
      >
        <el-option v-for="stock in availableStocks" :key="stock" :label="stock" :value="stock" />
      </el-select>

      <el-button type="primary" @click="searchData" :disabled="!selectedCode">検索</el-button>
    </div>

    <el-table v-if="tableColumns.length > 0 && tableData.length > 0" :data="tableData" border style="width: 100%; margin-top: 20px;" :fit="true">
      <el-table-column v-for="column in tableColumns" :key="column.prop" :prop="column.prop" :label="column.label"
        :width="column.width || 'auto'" />
    </el-table>

    <span slot="footer" class="dialog-footer">
      <el-button @click="exportToExcel">出力</el-button>
      <el-button @click="handleClose">閉じる</el-button>
    </span>
  </el-dialog>
</template>

<script>
import { getTableData, getAllTableData, getAllOptions, getMonthsByFcode, getStocksByFcodeAndMonth  } from "@/api/table";
import * as XLSX from "xlsx";

export default {
  props: {
    visible: {
      type: Boolean,
      required: true,
    }
  },
  data() {
    return {
      dialogVisible: this.visible,
      selectedCode: "",
      selectedMonth: "",
      selectedStock: "",
      loading: false,
      tableColumns: [],
      tableData: [],
      filteredOptions: [],
      allOptions: [],
      availableMonths: [],
      availableStocks: [],
      selectedFundType:"",
      stock:'',
    };
  },
  mounted() {
    const fundTypeRaw = this.$route.query.fundType;
    this.selectedFundType = fundTypeRaw === '公募' ? 'public' :
                        fundTypeRaw === '私募' ? 'private' : 'public';
  },
  watch: {
    visible(newValue) {
      this.dialogVisible = newValue;
    },
    dialogVisible(newVal) {
      this.$emit('update:visible', newVal);
      if (this.dialogVisible) {
        this.fetchOptions();
        this.tableData = [];
        this.tableColumns = [];
        this.selectedCode = "";
        this.selectedMonth = "";
        this.selectedStock = "";
      }
    }
  },
  computed: {
    deduplicatedOptions() {
      const seen = new Set();
      return this.filteredOptions.filter(item => {
        if (seen.has(item.fcode)) return false;
        seen.add(item.fcode);
        return true;
      });
    }
  },
  methods: {
    async fetchAllTableData() {
      const response = await getAllTableData();
      if (response.code === 200) {
        this.tableColumns = [
          { prop: "fcode", label: "Fコード" },
          { prop: "months", label: "決算月" },
          { prop: "stocks", label: "組入銘柄" },
          { prop: "組入銘柄解説", label: "組入銘柄解説" }
        ];
        this.tableData = response.data || [];
      }
    },
    async fetchOptions() {
      this.loading = true;
      try {
        const response = await getAllOptions({ 
          fundType: this.selectedFundType,
          fcode: "",
          stock: "",
          month: "",
        });
        if (response.code === 200) {
          this.allOptions = response.data;
          this.filteredOptions = this.allOptions;
        }
      } finally {
        this.loading = false;
      }
    },
    filterOptions(query) {
      this.filteredOptions = this.allOptions.filter(item =>
        String(item.fcode).toLowerCase().includes(query.toLowerCase())
      );
        // 🔽 可选：若查询为空，清空表格（用于手动清空搜索框时）
      if (!query) {
        this.tableData = [];
        this.tableColumns = [];
      }
    },
    async onFcodeChange() {
      this.selectedMonth = "";
      this.selectedStock = "";
      this.availableMonths = [];
      this.availableStocks = [];
      // 🔽 新增：Fコード清空时，清空表格数据
      if (!this.selectedCode) {
        this.tableData = [];
        this.tableColumns = [];
        return;
      }

      const code = String(this.selectedCode).trim();
      // const stock = String(this.selectedStock).trim();

      const responseMonth = await getMonthsByFcode({
        fcode: code,
        stock: this.selectedStock || "",
        fundType: this.selectedFundType
      });
      console.log("----4444---",this.stock)
      if (responseMonth.code === 200) {
        this.availableMonths = responseMonth.data;
      }

      const responseStock = await getStocksByFcodeAndMonth({
        fcode: this.selectedCode,
        month: this.selectedMonth || "",
        fundType: this.selectedFundType
      });
      if (responseStock.code === 200) {
        this.availableStocks = responseStock.data;
      }
    },
    async onMonthChange() {
      const code = String(this.selectedCode).trim();
      const month = String(this.selectedMonth).trim();
      this.selectedStock = "";
      if (!this.selectedMonth) return;

      const responseStock = await getStocksByFcodeAndMonth({
        fcode: code,
        month: month || "",
        fundType: this.selectedFundType
      });
      if (responseStock.code === 200) {
        this.availableStocks = responseStock.data;
      }
    },
    onStockChange() {},
    async searchData() {
        const code = String(this.selectedCode).trim();
        const month = String(this.selectedMonth).trim();
        const stock = String(this.selectedStock).trim();

        if (!code) {
          this.$message.warning("Fコードを選択してください");
          return;
        }

        const response = await getTableData({
          fcode: code,
          month: month || "",
          stock: stock || "",
          fundType: this.selectedFundType
        });

        if (response.code === 200) {
          const rawData = response.data || [];
          if (rawData.length === 0) {
            this.tableColumns = [];
            this.tableData = [];
            this.$message.warning("該当するデータが見つかりませんでした");
            return;
          }

          const excludeKeys = [
            "id", "_attachments", "_etag", "_rid", "_self", "_ts",
            "修正あり過去銘柄NO.", "sheetname"
          ];

          const labelMap = {
            no: "No.",
            fcode: "Fコード",
            months: "決算月",
            stocks: "組入銘柄",
            組入銘柄解説: "組入銘柄解説",
            社会的課題: "社会的課題",
            コメント: "コメント",
            ESGコメント: "ESGコメント"
          };
          const preferredOrder = ["no", "fcode", "months", "stocks", "組入銘柄解説", "社会的課題", "コメント", "ESGコメント"];

          const firstRow = rawData[0];
          const dynamicKeys = Object.keys(firstRow).filter(
            key => !excludeKeys.includes(key)
          );

          // ✅ 统一 "No." / "NO." 为 "no"
          const normalizedKeys  = dynamicKeys.map(key => {
            return key === "No." || key === "NO." ? "no" : key;
          });

          // 按顺序排序
          const orderedKeys = [
            ...preferredOrder.filter(k => normalizedKeys.includes(k)),
            ...normalizedKeys.filter(k => !preferredOrder.includes(k))
          ];

          this.tableColumns = orderedKeys.map(key => {
            const column = {
              prop: key,
              label: labelMap[key] || key
            };

            if (key === "no") {
              column.width = 60;
            } else if (key === "fcode") {
              column.width = 100;
            } else if (key === "months") {
              column.width = 100;
            } else if (key === "stocks") {
              column.width = 150;
            }  else if (key === "社会的課題") {
              column.width = 150;
            } 

            return column;
          });

          this.tableData = rawData.map(row => {
            const result = {};
            dynamicKeys.forEach(key => {
              const mappedKey = key === "No." || key === "NO." ? "no" : key;
              result[mappedKey] = row[key];
            });
            return result;
          });
        } else {
          this.$message.error("データ取得失敗");
        }
      },
    exportToExcel() {
      if (!this.tableData || this.tableData.length === 0) {
        // 🔽 无数据时，直接根据 fundType 下载对应 URL 的文件
        const templateUrl =
          this.selectedFundType === "public"
            ? "https://nriazureaistudio.blob.core.windows.net/1225-container/10銘柄マスタ管理_公募.xlsx"
            : "https://nriazureaistudio.blob.core.windows.net/1225-container/10銘柄マスタ管理_私募.xlsx";

        const link = document.createElement("a");
        link.href = templateUrl;
        link.download = "10銘柄マスタ管理_公募.xlsx";
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        return;
      }

      const header = this.tableColumns.map(col => col.label);
      const data = this.tableData.map(row =>
        this.tableColumns.map(col => row[col.prop] || "")
      );

      const worksheet = XLSX.utils.aoa_to_sheet([header, ...data]);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "10銘柄マスタ管理");

      const fileName = `コメントファイル_${this.getCurrentDate()}.xlsx`;
      XLSX.writeFile(workbook, fileName);
    },

    getCurrentDate() {
      const now = new Date();
      const year = now.getFullYear();
      const month = String(now.getMonth() + 1).padStart(2, "0");
      const day = String(now.getDate()).padStart(2, "0");
      return `${year}${month}${day}`;
    },
    handleClose() {
      this.dialogVisible = false;
      this.$emit("update:visible", false);
    }
  }
};
</script>

<style scoped>
.search-box {
  display: flex;
  gap: 10px;
  align-items: center;
  margin-bottom: 20px;
}

.el-table {
  background: white;
}
</style>
