export function getHistoryData(page = 1, size = 15, fileName = "") {
  return axios.get(`${Vue.prototype.$apiUrl}/api/log_operate`,{ params: { page, size, fileName } }
    )
        .then(response => response.data)
        .catch(error => {
          console.error("❌ 获取日志失败:", error);
          return { success: false, data: [], total: 0 };
        });
  }


// 获取检查结果
export function getCheckResult(fileId) {
    return axios.get(`${Vue.prototype.$apiUrl}/api/getCheckResult?id=${fileId}`).then((res) => res.data);
  }