import axios from "axios";
import Vue from "vue";

export function getMenu({ type, page, page_size }) {
  return axios.post(`${Vue.prototype.$apiUrl}/api/menu`, { type, page, page_size })
    .then(response => response.data)
    .catch(error => {
      console.error("메뉴 데이터 가져오기 실패:", error);
      return { code: 500, data: [], total: 0 };
    });
}

export function getMenuAll(type) {
  return axios.post(`${Vue.prototype.$apiUrl}/api/menu_all`, {type})
    .then(response => response.data)
    .catch(error => {
      console.error("메뉴 데이터 가져오기 실패:", error);
      return { code: 500, data: [], total: 0 };
    });
}

// 获取错误日志 API
export function getErrorLog(fileId) {
  return axios.get(`/api/get-error-log`, {
    params: { fileId }
  })
  .then(response => response.data)
  .catch(error => {
    console.error("❌ 获取错误日志失败:", error);
    return { log: "エラー情報の取得に失敗しました" }; // 返回默认日志内容
  });
}

export function markAsReadAPI(mark, selectedId, type) {
  return axios.put(`${Vue.prototype.$apiUrl}/api/update_read_status`, { mark, selectedId, type });
}