<template>
    <el-dialog
      title="指定ファイル"
      :visible.sync="visible"
      width="40%"
      center
      @close="handleClose"
    >
      <div class="upload-container">
        <el-upload
          class="upload-demo"
          drag
          action="" 
        >
          <i class="el-icon-upload"></i>
          <p>支持 .docx</p>
          <p>可拖拽至此处上传</p>
          <el-button type="primary">上传文档</el-button>
        </el-upload>
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="handleClose">取消</el-button>
      </span>
    </el-dialog>
  </template>
  
  <script>
  export default {
    name: "FilePopup",
    props: {
      visible: {
        type: Boolean,
        required: true,
      },
    },
    methods: {
      handleUploadSuccess() {
        this.$message.success("文档上传成功！");
      },
      handleClose() {
        this.$emit("update:visible", false); // 关闭弹窗
      },
    },
  };
  </script>
  
  <style scoped>
  .upload-container {
    text-align: center;
    padding: 20px;
    border: 1px dashed #d9d9d9;
    border-radius: 6px;
    background-color: #f9f9f9;
  }
  .upload-demo {
    display: inline-block;
    width: 100%;
    height: 200px;
    line-height: 200px;
    text-align: center;
  }
  .el-upload p {
    margin: 0;
    font-size: 14px;
    color: #666;
  }
  .el-upload .el-icon-upload {
    font-size: 36px;
    color: #409eff;
    margin-bottom: 10px;
  }
  /* 全局隐藏滚动条 */
body, html {
    overflow: hidden; /* 禁止滚动条显示 */
  }
  
  /* 单独设置内容仍然可滚动 */
  .sidebar,
  .document-container {
    overflow-y: auto; /* 内容可滚动但滚动条不可见 */
    scrollbar-width: none; /* Firefox 隐藏滚动条 */
  }
  
  .sidebar::-webkit-scrollbar,
  .document-container::-webkit-scrollbar {
    display: none; /* Chrome、Edge 隐藏滚动条 */
  }
  
  </style>
  