<template>
  <div>
    <el-dialog title="ログ履歴" :visible.sync="localVisible" width="60%" @close="onPopupClose">
      <div class="popup-controls">
        <div class="input-row">
          <label class="input-label">検索:</label>
          <el-input v-model="searchPath" placeholder="検索したいファイル名を入力してください" class="path-input"></el-input>
          <el-button type="primary" @click="fetchHistoryData" class="action-button">検索</el-button>
        </div>
        <!-- <div class="input-row">
          <label class="input-label">パス:</label> -->
          <!-- <el-input v-model="filePath" placeholder="フォルダパスを貼り付けてください" class="path-input"></el-input>
          <el-button type="primary" @click="selectPath" class="action-button" >SAVE</el-button> -->
          <!-- <el-input v-model="filePath" :disabled="!isEditing" class="path-input"></el-input>
          <el-button type="primary" @click="toggleEdit">
            {{ isEditing ? '保存' : '編集' }}
          </el-button>
        </div> -->
      </div>

      <el-table :data="tableData" style="width: 100%; margin-top: 20px;" @row-click="handleRowClick">
        <el-table-column prop="id" label="No." width=80>
          <template #default="scope">
            {{ (currentPage - 1) * pageSize + scope.$index + 1 }}
          </template>
        </el-table-column>
        <el-table-column prop="fileName" label="ファイル名" width="200"></el-table-column>
        <el-table-column prop="path" label="処理種別" width="200"  :formatter="formatPathText"></el-table-column>
        <!-- <el-table-column prop="ip_address" label="ipアドレス" width="160"></el-table-column> -->
        <el-table-column prop="result" label="チェック結果" width=120></el-table-column>
        <!-- <el-table-column prop="username" label="ユーザー" width="120"></el-table-column> -->
        <el-table-column prop="created_at" label="操作時間" width="200" :formatter="formatJapaneseDate"></el-table-column>
        <!-- <el-table-column prop="method" label="パス" width=80  :formatter="formatMethodText"></el-table-column> -->


        <!-- <el-table-column prop="fund_type" label="Type" width=80></el-table-column> -->
        <!-- <template slot-scope="scope">
          {{ scope.row.fund_type === 'public' ? '公募' : '私募' }}
        </template> -->
        <!-- </el-table-column> -->
        <!-- <el-table-column label="選択" width="80">
          <template slot-scope="scope">
            <el-checkbox v-model="scope.row.selected"></el-checkbox>
          </template>
        </el-table-column> -->
      </el-table>

      <div class="table-footer">
        <!-- <el-button type="primary" @click="selectAll" class="footer-button">全選択</el-button> -->
        <el-button type="success" @click="exportSelected" class="footer-button">出力</el-button>
      </div>

      <el-pagination @size-change="handleSizeChange" @current-change="handleCurrentChange" :current-page="currentPage"
        :page-sizes="[10, 20, 50, 100]" :page-size="pageSize" layout="total, sizes, prev, pager, next"
        :total="totalCount" background class="custom-pagination"
        style="margin-top: 20px; display: flex; justify-content: center;">
      </el-pagination>

    </el-dialog>
    <check-result-popup :visible.sync="checkResultPopupVisible" :tableData="tableDataDetail" />

    <input ref="fileInput" type="file" webkitdirectory style="display: none" @change="handleFolderSelection" />
  </div>
</template>

<script>
import CheckResultPopup from "./CheckResultPopup.vue";
import { getHistoryData, getCheckResult } from "@/api/history"; // ✅ 导入API
import * as XLSX from "xlsx";
import { saveAs } from "file-saver";
export default {
  components: { CheckResultPopup },
  props: {
    visible: {
      type: Boolean,
      required: true,
    },
  },
  data() {
    return {
      isEditing: false,
      localVisible: this.visible,
      checkResultPopupVisible: false, // 控制 CheckResultPopup 显示
      searchPath: "",
      filePath: "",
      allTableData: [], // ✅ 存储完整数据，保证搜索后可以恢复
      tableData: [], // ✅ 显示用数据（搜索/分页 후 변경됨）
      tableDataDetail: [],
      currentPage: 1, // ✅ 현재 페이지
      pageSize: 10, // ✅ 페이지당 데이터 수
      totalCount: 0,
    };
  },
  watch: {
    visible(val) {
      this.localVisible = val;
      if (val) {
        this.currentPage = 1;
        // ✅ 重新打开弹窗时，再次从 localStorage 取值
        const savedCheckPath = localStorage.getItem("individualCheckPath");
        if (savedCheckPath) {
          this.filePath = savedCheckPath;
        }
        this.fetchHistoryData(); // ✅ 重新获取表格数据
      }
    },
    localVisible(val) {
      this.$emit("update:visible", val);
    },
  },
  mounted() {
    // ✅ 读取 localStorage 的 `individualCheckPath`
    const savedCheckPath = localStorage.getItem("individualCheckPath");
    if (savedCheckPath) {
      this.filePath = savedCheckPath;
    }

    // ✅ 加载初始数据
    this.fetchHistoryData();
  },

  methods: {
    formatPathText(row) {
      if (row.path == '/api/save_corrections') {
        return 'チェック'
      } else if (row.path == '/api/check_file') {
        return 'アップロード'
      } else if (row.path == '/api/write_upload_save') {
        return 'アップロード/ダウンロード'
      }
    },
    formatMethodText(row) {
      if (row.method === 'POST') return 'ポスト';
      if (row.method === 'GET') return 'ゲット';
      if (row.method === 'PUT') return 'プット';
      return row.method;
    },
    formatJapaneseDate(row, column, cellValue) {
      if (!cellValue) return '';
      const date = new Date(cellValue);
      const yyyy = date.getFullYear();
      const mm = String(date.getMonth() + 1).padStart(2, '0');
      const dd = String(date.getDate()).padStart(2, '0');
      const hh = String(date.getHours()).padStart(2, '0');
      const min = String(date.getMinutes()).padStart(2, '0');
      const ss = String(date.getSeconds()).padStart(2, '0');

      return `${yyyy}年${mm}月${dd}日 ${hh}:${min}:${ss}`;
    },
    toggleEdit() {
      this.isEditing = !this.isEditing;
      const path = this.filePath.trim();
      if (path) {
        // 保存処理など
        // console.log("保存パス:", path);
      } else {
        this.$message.error("フォルダパスを入力してください");
      }
    },
    // selectPath() {
    //   const path = this.filePath.trim();
    //   if (path) {
    //     // 保存処理など
    //     // console.log("保存パス:", path);
    //   } else {
    //     this.$message.error("フォルダパスを入力してください");
    //   }
    // },

    // ✅ 选择文件夹
    selectFolderPath() {
      this.$refs.fileInput.click(); // 触发文件选择
    },

    // ✅ 处理文件夹选择
    handleFolderSelection(event) {
      const files = event.target.files;
      if (files.length > 0) {
        // ✅ 获取文件夹路径（去掉文件名）
        const filePath = files[0].webkitRelativePath || files[0].name;
        this.filePath = filePath.substring(0, filePath.lastIndexOf("/"));
      }
      this.$refs.fileInput.value = ""; // 清空 input，确保可以重复选择
    },
    async fetchHistoryData() {
      try {
        // 로컬 스토리지에서 데이터 가져오기
        // const cachedData = localStorage.getItem("historyData");
        // if (cachedData) {
        //   this.allTableData = JSON.parse(cachedData);
        //   this.tableData = [...this.allTableData]; // 초기 데이터 설정 .slice(-50)
        //   return; // 로컬 스토리지에서 데이터를 가져온 경우, API 호출을 하지 않음
        // }

        // API를 통해 데이터를 가져옵니다.
        // const response = await getHistoryData();
        const response = await getHistoryData(this.currentPage, this.pageSize, this.searchPath);
        if (response.success) {
          // this.allTableData = response.data;
          // this.tableData = [...this.allTableData]; // 초기 데이터 설정
          if (response.success) {
            this.allTableData = response.data;
            this.tableData = [...response.data];
            this.totalCount = response.total;
          }

          // 로컬 스토리지에 데이터 저장
          // localStorage.setItem("historyData", JSON.stringify(this.allTableData));
          localStorage.setItem("historyData", JSON.stringify(this.totalCount));

          // console.log("📌 取得履歴データ:", this.tableData);
        } else {
          // this.$message.error("履歴データの取得に失敗しました");
        }
      } catch (error) {
        console.error("履歴データ取得エラー:", error);
        // this.$message.error("履歴データの取得に失敗しました");
      }
    },

    // ✅ 只匹配 `ファイル名`（tableData.name）的模糊搜索
    async handleSearch() {
      this.currentPage = 1; // 검색 시 첫 페이지로 이동
      if (!this.searchPath.trim()) {
        // 如果搜索框为空，则显示所有数据
        this.tableData = [...this.allTableData];
        this.$message.info("全てのデータを表示します");
        return;
      }

      // 转小写，忽略大小写搜索
      const response = await getHistoryData(this.currentPage, this.pageSize, this.searchPath);
      if (response.success) {
        this.tableData = [...response.data];
        this.totalCount = response.total;
        console.log(response)
      }

      if (this.tableData.length === 0) {
        this.$message.warning("該当するファイルが見つかりませんでした");
      } else {
        this.$message.success(`${this.tableData.length} 件のファイルが見つかりました`);
      }
    },
    closePopup() {
      this.localVisible = false;
    },
    onPopupClose() {
      this.searchPath = "";
      this.filePath = "";
      this.currentPage = 1; // 弹窗关闭时重置页码
      this.isEditing = false
    },
    confirmPath() {
      this.$message.success("パスが確認されました！");
    },
    handleRowClick(row) {
      console.log("行クリック: ", row);
    },
    async handleFileLinkClick(row) {
      // console.log("文件链接点击:", row);

      // 1️⃣ 先清空已有数据
      this.selectedRow = null;
      this.tableDataDetail = [];

      // 2️⃣ 记录当前点击的行
      this.selectedRow = row;

      try {
        // 3️⃣ 发送 API 请求获取检查结果
        const response = await getCheckResult(row.id);

        // 4️⃣ 更新数据（如果 API 返回 data）
        if (response.code === 200) {
          this.tableDataDetail = response.data || [];
        } else {
          this.$message.error("チェック結果の取得に失敗しました");
        }
      } catch (error) {
        console.error("获取检查结果失败:", error);
        this.$message.error("チェック結果の取得に失敗しました");
      }

      // 5️⃣ 显示弹窗
      this.checkResultPopupVisible = true;
    },

    selectAll() {
      // ✅ 현재 페이지의 데이터만 선택/해제
      this.pagedTableData.forEach(row => (row.selected = true));
    },
    async exportSelected() {
      // ✅ 过滤出所有数据中选中的行
      const response = await getHistoryData(1, this.totalCount, this.searchPath)
      const exportData = response.data;

      // ✅ 创建工作表
      const ws = XLSX.utils.json_to_sheet(exportData);

      // ✅ 创建工作簿
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "チェック履歴");

      // ✅ 生成 Excel 并触发下载
      const excelBuffer = XLSX.write(wb, { bookType: "xlsx", type: "array" });
      const fileName = `チェック履歴_${new Date().toISOString().slice(0, 10)}.xlsx`;

      saveAs(new Blob([excelBuffer], { type: "application/octet-stream" }), fileName);

      this.$message.success("Excelファイルを出力しました");
    },
    handleSizeChange(val) {
      this.pageSize = val;
      this.currentPage = 1;
      this.fetchHistoryData();
    },
    handleCurrentChange(val) {
      this.currentPage = val;
      this.fetchHistoryData();
    },
    // // ✅ 페이지 크기 변경 시 호출
    // handleSizeChange(val) {
    //   this.pageSize = val;
    //   this.currentPage = 1; // 페이지 크기 변경 시 첫 페이지로 이동
    // },

    // // ✅ 현재 페이지 변경 시 호출
    // handleCurrentChange(val) {
    //   this.currentPage = val;
    // },
  },

  // ✅ 계산된 속성: 현재 페이지에 표시할 데이터
  computed: {
    pagedTableData() {
      const start = (this.currentPage - 1) * this.pageSize;
      const end = start + this.pageSize;
      return this.tableData.slice(start, end);
    },
  },
};
</script>

<style scoped>
/* 기존 스타일 유지 */
.popup-controls {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 10px;
}

.input-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  width: 100%;
}

.input-label {
  width: 80px;
  text-align: right;
  font-weight: bold;
}

.path-input {
  flex-grow: 1;
}

.action-button {
  white-space: nowrap;
}

.table-footer {
  display: flex;
  justify-content: flex-end;
  margin-top: 10px;
  gap: 10px;
}

.footer-button {
  width: 100px;
}
</style>