                            </el-menu-item>
                          </el-submenu>
                        </template>
                      </el-submenu>
                    </template>
                  </el-submenu>
                </template>

                <!-- ✅ 处理其他普通子菜单项（非既読 /未読） -->
                <template v-for="subItem in item.children">
                  <el-submenu
                    v-if="subItem.children && subItem.children.length && subItem.id !== 'read' && subItem.id !== 'unread'"
                    :key="subItem.id" :index="subItem.id">
                    <template slot="title">
                      <span class="menu-title">{{ subItem.name }}</span>
                    </template>

                    <el-menu-item v-for="fileItem in subItem.children" :key="fileItem.id" :index="fileItem.id"
                      style="color: white; opacity: 1; filter: none;" disabled>
                      {{ fileItem.name }}
