          <!-- <div v-if="allLoaded" style="text-align:center;padding:8px;">すべてのデータを呼び出しました。</div> -->
        </el-scrollbar>


      </el-aside>
      <el-container>
        <el-main v-loading="isLoading">
          <check-fund-detail ref="checkFundDetail" :selectedId="selectedId" :selectedFile="selectedFile"
            :selectedFolder="selectedFolder" :selectedPdfPath="selectedPdfPath" :fundType="fundType"
            :currentPage="currentPage" :totalPages="totalPages" @totalPages="handlePageChange"
            @page-changed="handlePageChange" />
        </el-main>
      </el-container>
    </el-container>

    <file-popup :visible.sync="isFilePopupVisible" />
    <MenuComponent :menuData="menuData" />
    <path-popup :visible.sync="isPathPopupVisible" :selectedFolder="selectedFolder" @updateMenu="fetchMenuAllData"
      @fileUploaded="handleFileUploaded" @loaded="fetchErrorCount" />
    <path-popup-1 :visible.sync="isPathPopupVisible1" :selectedFolder="selectedFolder" @updateMenu="fetchMenuAllData"
      @fileUploaded="handleFileUploaded" />
    <result-popup :visible.sync="isResultPopupVisible" />
    <m10-popup :visible.sync="is10PopupVisible" />
    <!-- <ErrorLogPopup 
      :visible.sync="isErrorPopupVisible"
      :fileId="selectedErrorFileId"
    />
    <ErrorLogPopup1
      :visible.sync="isErrorPopupVisible1"
    /> -->

  </div>
