<script>
import CheckFundDetail from './CheckFundDetail.vue';
import FilePopup from './FilePopup.vue';
import PathPopup from './PathPopup.vue';
import PathPopup1 from './PathPopup1.vue';
import ResultPopup from './ResultPopup.vue';
import M10Popup from './M10Popup.vue';
import { getMenu, getMenuAll, markAsReadAPI } from "@/api/menu";
import { startAutoCheck, checkAutoCheck } from "@/api/check";
// import ErrorLogPopup from "@/components/ErrorLogPopup.vue"; // 确保路径正确
// import ErrorLogPopup1 from "@/components/ErrorLogPopup1.vue"; // 确保路径正确
// import { getErrorLogCount } from "@/api/errorLog"; // 引入获取错误日志数量的API
import MenuComponent from "@/components/MenuComponent.vue";
import Vue from "vue";

export default {
  name: "MainLayout",
  components: { CheckFundDetail, FilePopup, PathPopup, PathPopup1, ResultPopup, M10Popup, MenuComponent },
  data() {
    return {
      fundType: this.$route.query.fundType || '公募',
      isCollapsed: false,
      isUsernameVisible: false,
      username: '管理者',
      selectedFile: '', // ✅ 초기값 설정 (빈 문자열)
      isFilePopupVisible: false,
      isPathPopupVisible: false,
      isPathPopupVisible1: false,
      isResultPopupVisible: false,
      toolStatus: '停止',
      downloadStatus:'',
      controller: null,
      selectedFundType: '公募',
      is10PopupVisible: false,
      menuData: [],
      activeMenu: "1",
      selectedStatus: "",
      selectedReadStatus: "",
      statusOptions: [
        { label: "すべて", value: "", color: "transparent" },
        { label: "未チェック", value: "unchecked", color: "gray" },
        { label: "問題あり", value: "issue", color: "yellow" },
        { label: "問題なし", value: "no_issue", color: "green" },
        { label: "エラー発生", value: "error", color: "red" },
      ],
      readStatusOptions: [
        { label: "すべて", value: "すべて" },
        { label: "既読 ", value: "read" },
        { label: "未読", value: "unread" },
      ],
      // selectedPdfPath: "",
      selectedId: "",
      selectedFolder: "",
      isErrorPopupVisible: false,
      selectedErrorFileId: "",
      selectedErrorFileName: "",
      isErrorPopupVisible1: false,
      errorCount: 0,
      uploadedFiles: [],
      selectedFileRaw: null,
      isLoading: false,
      selectedPdfPath: '',
      icon: '✅',
      title_selectedFile: '',
      targetText: '',
      DEBUG: false,
      debug_pdfurl:'180010-1_M2501.pdf',
      DEBUG_KANJI: true,
      DEBUG_RURU: true,
      page: 1,
      pageSize: 20,
      total: 0,
      loadingMenu: false,
      allLoaded: false,
      loadData: [],
      currentPage: 1,  // 현재 페이지 초기화
      totalPages: 1,  // 현재 페이지 초기화
      pageTexts: [],
      gptCache: {}, // 입력값 → 결과 캐시 저장소
    };
  },
  computed: {
    // ✅ 自动按钮的文本
    buttonLabel() {
      return this.toolStatus === "自動運行中" ? "自動チェック停止" : "自動チェック開始";
    },
    // ✅ 手动按钮的文本
    manualButtonLabel() {
      return this.toolStatus === "手動運行中" ? "手動チェック停止" : "手動チェック";
    },
    // ✅ 自动按钮的颜色：默认状态无颜色，运行中变红
    buttonType() {
      return this.toolStatus === "自動運行中" ? "danger" : "default";
    },
    // ✅ 手动按钮的颜色：默认状态无颜色，运行中变红
    manualButtonType() {
      return this.toolStatus === "手動運行中" ? "danger" : "default";
    },
    // ✅ 是否自动运行中
    isAutoRunning() {
      return this.toolStatus === "自動運行中";
    },
    // ✅ 是否手动运行中
    isManualRunning() {
      return this.toolStatus === "手動運行中";
    },
    isDownloading() {
    return this.downloadStatus === "PDFダウンロード中...";
  }
  },
  mounted() {
    this.$nextTick(() => {
      const scrollWrap = this.$refs.menuScroll.$refs.wrap;
      if (scrollWrap) {
        scrollWrap.addEventListener('scroll', this.onMenuScroll);
      }
    });
    this.selectedFundType = this.$route.query.fundType || '公募';
    this.selectedStatus = ""; // 默认显示全部
    this.checkAutoButtonClick();
    this.fetchErrorCount(); // 组件加载时获取警告个数
  },
  beforeDestroy() {
    if (this.menuUpdateInterval) {
      clearInterval(this.menuUpdateInterval);
      // console.log("🛑 停止菜单自动刷新");
    }
    const scrollWrap = this.$refs.menuScroll.$refs.wrap;
    if (scrollWrap) {
      scrollWrap.removeEventListener('scroll', this.onMenuScroll);
    }

  },

  created() {
    this.selectedFundType = this.$route.query.fundType || '公募';
    this.selectedStatus = ""; // 默认显示全部

    this.fetchMenuAllData(); // 加载菜单 for startbuttonA
    this.fetchMenuData(); // 加载菜单
  },
  buttonType() {
    if (this.isAutoRunning) return "danger"; // 运行中，红色
    if (this.isManualRunning) return "locked"; // 被锁定，灰色
    return "default"; // 默认
  },
  manualButtonType() {
    if (this.isManualRunning) return "danger";
    if (this.isAutoRunning) return "locked";
    return "default";
  },
  methods: {
    handlePageChange(newPage) {
      this.currentPage = 1;  // currentPage 업데이트
      console.log("currentPage:", this.currentPage);
      console.log("newPageページ:", newPage);
      this.totalPages = newPage
      console.log("Total:", this.totalPages);
    },
    mergeMenuData(targetList, newList) {
      newList.forEach(newItem => {
        // name and id
        const existingItem = targetList.find(item => item.id === newItem.id || item.name === newItem.name);
        if (existingItem) {
          if (newItem.children && existingItem.children) {
            this.mergeMenuData(existingItem.children, newItem.children);
          }
        } else {
          targetList.push(newItem);
        }
      });
    }

    ,
    async loadMenuData() {
      if (this.loadingMenu || this.allLoaded) return;
      this.loadingMenu = true;
      try {
        const response = await getMenu({
          type: this.selectedFundType === '私募' ? 'private' : 'public',
          page: this.page,
          page_size: this.pageSize,
        });

        if (response.code === 200) {
          // ✅ 빈 배열이면 더 이상 요청하지 않음
          const rawData = response.data;
          if (!rawData || rawData.length === 0) {
            this.allLoaded = true;
            return;
          }
          // transformMenuData가 필요하다면 적용
          const newData = this.transformMenuData ? this.transformMenuData(rawData) : rawData;
          // this.menuData = this.menuData.concat(newData);

          // ✅ 트리 병합
          this.mergeMenuData(this.menuData, newData);

          this.total = response.total;
          if (this.menuData.length >= this.total) {
            this.allLoaded = true;
          } else {
            this.page += 1;
          }
          if (!this.selectedFile && this.menuData.length > 0) {
            this.selectFirstFile();
          }
        } else {
          console.error("❌ 메뉴 데이터 로드 실패:", response.message);
        }
      } catch (error) {
        console.error("❌ 메뉴 데이터 요청 중 오류:", error);
      } finally {
        this.loadingMenu = false;
      }
    },


    onMenuScroll() {
      const scrollContainer = this.$refs.menuScroll.$refs.wrap;
      if (scrollContainer.scrollTop + scrollContainer.clientHeight >= scrollContainer.scrollHeight - 100) {
        this.loadMenuData();
      }
    },
    // ✅ transformToMenuData 함수 추가
    transformToMenuData(apiData) {
      const menuData = {
        公募: [
          {
            id: "reference",
            name: "📁 参照ファイル",
            children: [
              {
                id: "report_data",
                name: "📂 レポートデータ",
                children: [], // to be populated
              },
              {
                id: "mingbing_data",
                name: "📂 10銘柄解説一覧表",
                children: [], // to be populated
              },
            ],
          },
          {
            id: "checked_files",
            name: "📁 チェック対象ファイル",
            children: [
              {
                id: "individual_comments",
                name: "📂 共通コメントファイル",
                children: [], // to be populated
              },
              {
                id: "kobetsucomment",
                name: "📂 個別コメントファイル",
                children: [], // to be populated
              },
            ],
          },
        ],
        私募: [
          {
            id: "reference",
            name: "📁 参照ファイル",
            children: [
              {
                id: "report_data",
                name: "📂 レポートデータ",
                children: [], // to be populated
              },
              {
                id: "mingbing_data",
                name: "📂 10銘柄解説一覧表",
                children: [], // to be populated
              },
            ],
          },
          {
            id: "checked_files",
            name: "📁 チェック対象ファイル",
            children: [
              {
                id: "individual_comments",
                name: "📂 共通コメントファイル",
                children: [], // to be populated
              },
              {
                id: "kobetsucomment",
                name: "📂 個別コメントファイル",
                children: [], // to be populated
              },
            ],
          },
        ],
      };

      // ✅ 公募 또는 私募 판단
      const category = apiData.code === 200 ? "公募" : "私募"; // Replace with appropriate condition to check category


      // ✅ reference 데이터 추가
      const referenceData = apiData.corrections.map((item, index) => ({
        id: index.toString(),
        name: item.fileName,
        icon: "📄",
        file: item.fileName,
        pdfPath: item.link,
      }));

      const mingbingData = referenceData; // Reusing the same data for mingbing_data, adjust if needed

      // ✅ reference 데이터 추가
      menuData[category][0].children[0].children_report = referenceData; // report_data
      menuData[category][0].children[1].children = mingbingData; // mingbing_data

      // ✅ checked_files 데이터 추가
      const individualComments = apiData.corrections.map((item, index) => ({
        id: (index + 6).toString(),
        name: `修正コメント - ${item.fileName}`,
        icon: "✅",
        file: item.fileName,
        status: item.status,
        readStatus: item.readStatus,
        pdfPath: item.link,
      }));
      const kobetsuComments = individualComments; // Reusing the same data for kobetsucomment, adjust if needed

      // ✅ checked_files 데이터 추가
      menuData[category][1].children[0].children = individualComments; // individual_comments
      menuData[category][1].children[1].children = kobetsuComments; // kobetsucomment

      // console.log(menuData, 'menuDatamenuData')
      return menuData;
    },
    async fetchFileFromUrl(url, fileName) {
      const response = await fetch(url);
      const blob = await response.blob();
      return new File([blob], fileName, { type: blob.type });
    },
    split_text(text, maxLength) {
      const chunks = [];
      let startIndex = 0;
      while (startIndex < text.length) {
        const endIndex = startIndex + maxLength;
        chunks.push(text.slice(startIndex, endIndex));
        startIndex = endIndex;
      }
      return chunks;
    },
    async handleFileUploaded({ id, fileName, uploadResult, folder, fundType, raw }) {

      // 상태 업데이트
      this.selectedId = id;
      const idx = this.uploadedFiles.findIndex(f => f.id === id || f.fileName === fileName);

      if (idx !== -1) {
        this.uploadedFiles[idx] = { id, fileName, raw };
      } else {
        this.uploadedFiles.push({ id, fileName, raw });
      }
      this.selectedFile = fileName;
      console.log('--------------------------------------')
      console.log(this.selectedFile)
      this.selectedFolder = `📂 ${folder}`; // 폴더 이름 형식 맞추기
      this.fundType = fundType;

      // === localStorage에 파일 메타정보 저장 (raw는 저장 불가) ===
      const fileMetaList = JSON.parse(localStorage.getItem('uploadedFileMetaList') || '[]');
      // 중복 제거
      const newMeta = { id, fileName, folder, fundType, uploadResult };
      const filtered = fileMetaList.filter(f => f.id !== id && f.fileName !== fileName);
      filtered.push(newMeta);
      localStorage.setItem('uploadedFileMetaList', JSON.stringify(filtered));

      // CheckFundDetail 컴포넌트의 fetchCheckResults 호출 시 업로드 결과 전달
      this.$nextTick(() => {
        if (this.$refs.checkFundDetail) {
          // console.log("📌 call check function:", {
          //   id,
          //   folder: this.selectedFolder,
          //   fundType: this.fundType
          // });
          this.$refs.checkFundDetail.fetchCheckResults(id, uploadResult);
        }
      });
    },
    async markAsRead(mark) {
      // console.log("✅ 标记为已读:", mark);
      try {
        const response = await markAsReadAPI(mark, this.selectedId, this.selectedFundType === '私募' ? 'private' : 'public');
        // console.log("📌 API 返回:", response.data);

        if (response.data.code == 200) {
          this.$message.success(mark == "read" ? "✅ 既読としてマークされました！" : "✅ 未読としてマークされました！");
          // update menu list 
          this.fetchMenuData();
        } else {
          this.$message.error("❌ファイルの状態を確認してください：" + response.data.message);
        }
      } catch (error) {
        console.error("❌ 未読 error:", error);
        this.$message.error("❌ マークerror！");
      }
    },

    async fetchErrorCount() {
      const cachedData = localStorage.getItem("historyData");

      if (cachedData) {
        try {
          const parsed = JSON.parse(cachedData);
