    transformMenuData(apiData) {
      const menuData = [];

      const unreadFiles = apiData.filter(item => item.readStatus !== "read" && item.upload_type != "参照ファイル");
      const readFiles = apiData.filter(item => item.readStatus === "read" && item.upload_type != "参照ファイル");
      const referFiles = apiData.filter(item => item.upload_type == "参照ファイル");

      const createFileData = (items) => items.map((item) => ({
        id: item.id,
        name: item.fileName,
        icon: item.result.corrections.length > 0 ? "⚠️" : item.icon,
        file: item.fileName,
        pdfPath: item.link,
        status: item.status
      }));

      const creatreferFileData = (items) => items.map((item) => ({
        id: item.id,
        name: item.fileName,
        file: item.fileName,
        pdfPath: "",
        status: ""
      }));

      menuData.push({
        id: "reference",
        name: "📁 参照ファイル",
        children: [
          {
            id: Date.now().toString(36) + Math.random().toString(36).substr(2, 5),
            name: "📂 レポートデータ",
            children: creatreferFileData(referFiles),
          },
          {
            id: Date.now().toString(36) + Math.random().toString(36).substr(2, 5),
            name: "📂 10銘柄解説一覧表",
            children: [],
          },
        ],
      });

      // 按月份分组函数（使用 _ts 时间戳）
      const groupByMonth = (items) => {
        const grouped = {};
        
        items.forEach(item => {
          let monthKey = "unknown";
          
          if (item._ts) {
            // 处理时间戳（可能是秒或毫秒）
            const timestamp = typeof item._ts === "number" 
              ? (item._ts < 1e12 ? item._ts * 1000 : item._ts) // 如果是秒转换为毫秒
              : new Date(item._ts).getTime(); // 处理字符串格式
            
            const date = new Date(timestamp);
            const year = date.getFullYear();
            const month = date.getMonth();
            monthKey = `${year}${month.toString().padStart(2, '0')}`;
          }
          
          if (!grouped[monthKey]) grouped[monthKey] = [];
          grouped[monthKey].push(item);
        });
        
        return grouped;
      };

      // 分组未读和已读文件
      const unreadGroups = groupByMonth(unreadFiles);
      const readGroups = groupByMonth(readFiles);

      // 创建月份分组下的子菜单
      const createMonthChildren = (items, prefix) => {
        return Object.keys(items)
          .sort((a, b) => b.localeCompare(a)) // 按时间倒序排序
          .map(month => ({
            id: `${prefix}_${month}`,
            name: `📂 ${month.substring(0, 4)}${month.substring(4, 6)}`,
            children: [
              {
                id: `${prefix}_common_${month}`,
                name: "📂 共通コメントファイル",
                children: createFileData(
                  items[month].filter(item => item.comment_type === "共通コメントファイル")
                ),
              },
              {
                id: `${prefix}_kobetsu_${month}`,
                name: "📂 個別コメントファイル",
                children: createFileData(
                  items[month].filter(item => item.comment_type !== "共通コメントファイル")
                ),
              }
            ]
          }));
      };

      menuData.push({
        id: "checked_files",
        name: "📁 チェック対象ファイル",
        children: [
          {
            id: "unread",
            name: "📂 未読",
            children: createMonthChildren(unreadGroups, "unread"),
          },
          {
            id: "read",
            name: "📂 既読",
            children: createMonthChildren(readGroups, "read"),
          },
        ],
      });

      return menuData;
    },

    // ✅ 递归查找菜单中的第一个文件
    findFirstFile(menu) {
      for (const item of menu) {
        if (item.children && item.children.length) {
          const foundFile = this.findFirstFile(item.children);
          if (foundFile) return foundFile;
        } else if (item.pdfPath) {
          return item;  // 找到第一个有 pdfPath 的文件
        }
      }
      return null;
    },
