          ? this.selectedReferenceCategory
          : this.selectedCategory

        // debug
        const fileUrl = this.DEBUG ? `/files/${this.debug_pdfurl}` : this.selectedPdfPath;

        // 1. URL에서 파일 받아오기 /^(\d+)(?:-\d+)?[_-](M\d{4})[^.]*\.(pdf|xlsx)$/i
        const fileName = fileUrl.split('/').pop();
        const fileFromLink = await this.fetchFileFromUrl(fileUrl, fileName);

        const checkStatus = () => {
          if (this.toolStatus === "停止") {
            throw new Error('USER_ABORT');
          }
        };

        const formData = new FormData();
        formData.append('files', fileFromLink);
        formData.append('fundType', this.fundType === '私募' ? 'private' : 'public');
        formData.append('category', targetCategory);
        formData.append('uploadMethod', this.selectedMethod);
        formData.append('filePath', this.filePath);

        const uploadResponse = await fetch(`${Vue.prototype.$apiUrl}/api/check_upload`, {
          method: 'POST',
          body: formData,
          signal
        });
        checkStatus();
        const uploadResult = await uploadResponse.json();
        if (!uploadResult.success) throw new Error(uploadResult.error || 'upload error');

        // async call api
        let gptResults = [];
        let fetchPromises = [];

        const pageList = uploadResult.original_text || [];


        for (const [text, pageNumber] of pageList) {
          // check include O
          const checkO = text.includes("○") || text.includes("〇")
          if (!checkO) {
            const rawMatches = text
              .replace('先月の運用経過', '')
              .replace('先月の投資環境', '')
              .match(/(?=マンスリーアップデート|(\d{1,2})月のパフォーマンス動向|米国地方一般財源保証債の組み入れを高位に保ちました。|=?現在\n・|=?【債券市場】)[\s\S]*?(?=ファンドは|本ファンドの受益証券の価格は、|この報告書は、|当ファンドは|（出所）KKR等から)/gs);
            
            this.targetText = rawMatches ? rawMatches[0] : text;
            this.matches = this.targetText.match(/.*?。|.+$/gs) || [];

          }

          if (checkO) {
            const rawMatches = text
              .replace('先月の運用経過', '')
              .replace('先月の投資環境', '')
              // .match(/(トヨタグループ企業債券[\s\S]*?(?=〇|○|ファンドは、値動|$)|(?<!\d)1(?!\d)[\s\S]*?(?=〇|○|組入銘柄|組入上位10銘柄の解説|10銘柄の解説|ファンドは、値動|$)|[〇○].*?(?=〇|○|本ファンドの|組入上位10銘柄の解説|今後の運用方針|組入上位銘柄(?!のうち)|ファンドは、値動|〔登録番号|■ファンドは|〇|○|$))/gs)
              .match(/((トヨタグループ企業債券|【投資環境】)[\s\S]*?(?=〇|○|ファンドは、値動|$)|(?<!\d)1\n(?![0-9\-－]+(\s*円)?(\n|$))[\s\S]*?(?=〇|○|組入銘柄|組入上位10銘柄の解説|10銘柄の解説|ファンドは、値動|$)|[〇○◯].*?(?=〇|○|◯|本ファンドの|組入上位10銘柄の解説|今後の運用方針|組入上位銘柄(?!のうち)|ファンドは、値動|〔登録番号|■ファンドは|この報告書は、|〇|○|$))/gs)
            
            // this.targetText = rawMatches ? rawMatches[0] : text;
            // this.matches = this.targetText.match(/.*?。|.+$/gs) || [];

            // Preprocessing , 10銘柄 分段处理
            this.matches = rawMatches.flatMap(block => {
              if (block.startsWith("1")) {
                return block
                  .split(/\n(?=\d{1,2}(?:\s+\d+)?\s+[^\d\s]{2,50})/) // 각 항목 시작을 줄바꿈+숫자로 분할
                  .map(b => b.trim())
                  .filter(b => b !== '')
                  .map(b => {
                    // 예: "1 0 フジクラ 大手国内電線メーカー。"
                    const match = b.match(/^\d+(?:\s+\d+)?\s+([^\d\s]{2,50})\s+([\s\S]*)$/);
                    if (match) {
                      const [, company, desc] = match;
                      return `${company.trim()}\n${desc.trim()}`;
                    }
                    return b; // 매칭 안 되면 원문 그대로
                  });
              } else {
                return [block];
