              for (let i = 0; i < text.length; i++) {
                buffer += text[i];

                // 문장 종결 문자 '。'에서 자르기 조건
                if (text[i] === '。' && buffer.length >= chunkSize) {
                  acc.push(buffer.trim());
                  buffer = '';
                }
              }

              // 남은 텍스트가 있다면 추가
