            .flatMap(r => r.corrections);
            
            }

            console.log(correctionsToSave, 'check dupli---startbuttonA-->')

            // DB update
            try {
              const update_response = await fetch(`${Vue.prototype.$apiUrl}/api/save_corrections`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  file_name: uploadResult.file_name,
                  corrections: correctionsToSave,
                  fund_type: this.fundType === '私募' ? 'private' : 'public',
                  pdf_base64: uploadResult.pdf_bytes,
                  icon: this.icon,
                }),
                signal
              });
              const result = await update_response.json();
              if (result.success) {
                this.$message.success('DB save success!');

                // ⬇️ Dload
                  const downloadToken = result.pdf_download_token;
                  if (downloadToken) {
                    const downloadUrl = `${Vue.prototype.$apiUrl}/api/download_pdf/${encodeURIComponent(downloadToken)}`;
                    
                    fetch(downloadUrl)
                      .then(response => response.blob())
                      .then(blob => {
                        this.toolStatus = "PDFダウンロード中...";
                        const url = window.URL.createObjectURL(blob);
                        const a = document.createElement('a');
                        a.href = url;
                        
                        // ✅ 실제 파일명으로 지정
                        // a.download = uploadResult.file_name.endsWith('.pdf')
                        //   ? uploadResult.file_name
                        //   : `${uploadResult.file_name}.pdf`;
                        a.download = uploadResult.file_name
                        a.click();
                        window.URL.revokeObjectURL(url);
                        this.toolStatus = "PDFダウンロード成功";
                      })
                      .catch(error => {
                        console.error("Download failed:", error);
                        this.downloadStatus = "PDFダウンロード失敗";
                      })
                      .finally(() => {
                        this.toolStatus = "PDFダウンロード成功";
                        // setTimeout(() => {
                        //   if (this.toolStatus !== "停止") {
                        //     this.toolStatus = "停止";
                        //   }
                        // }, 2000);
                      });
                  }

              } else {
                this.$message.error('DB save error: ' + (result.error || ''));
              }
            } catch (error) {
              console.error('DB save error:', error);
              this.$message.error('DB error.');
            }
            checkStatus();
            this.fetchMenuAllData();
            this.fetchErrorCount();

            this.$message.success("Select File Check Success!");
            // this.markAsRead('read');
            this.$nextTick(() => {
              if (this.$refs.checkFundDetail) {
                this.$refs.checkFundDetail.fetchCheckResults(uploadResult.file_name, uploadResult);
              }
            });
          } // loop list
        }// loop earch 8
        this.toolStatus = "停止"
      } catch (error) {
        if (error.message === 'USER_ABORT' || error.name === 'AbortError') {
          // console.log('用户主动停止');
          return;
        }
        console.error("アップロードエラー:", error);
        this.$message.error("Select File Check error: " + error.message);
      } finally {
        // this.isLoading = false;
        this.toolStatus = "停止";
        this.controller = null;
        this.title_selectedFile = '';
      }
    },


    // 메뉴에서 선택된 폴더 아래의 파일만 추출
    getAllFilesFromMenu(menuData) {
      const files = [];
      const selectedFolder = this.selectedFolder; // this.selectedFolder를 지역 변수로 저장

      function traverse(menu) {
        for (const item of menu) {
          if (item.children && item.children.length) {
            if (item.name === selectedFolder) {
              // 하위 children에서 파일만 추출 (⚠️ 아이콘이 아닌 것만)
              item.children.forEach(child => {
                if (
                  child.pdfPath
                  && child.name
                  && child.icon !== "⚠️" // for debug 722
                  && child.icon !== "✅"
                ) {
                  files.push({
                    name: child.name,
                    pdfPath: child.pdfPath
                  });
                }
              });
            } else {
              // 일치하지 않으면 하위로 계속 탐색
              traverse(item.children);
            }
          }
        }
      }

      traverse(menuData);
      return files;
    },

    // 폴더 또는 파일 클릭 시 경로를 처리하는 함수
    handleSubmenuClick(submenu) {
      // 폴더 이름 저장
      if (submenu && submenu.name) {
        // console.log("Clicked folder:", submenu.name);
        this.selectedFolder = submenu.name;
      }
    },

    stopBotton() {
      this.toolStatus = "停止";
    }
  },
};
