<template>
  <el-dialog
    title="パス指定"
    :visible.sync="localVisible"
    width="50%"
    :modal-append-to-body="false"
    @close="handleClose"
  >
    <div class="container">
      <!-- 左侧（インプットパス指定） -->
      <div class="left-section">
        <h3>インプットパス指定</h3>

        <!-- <div class="input-group">
          <span class="label">レポートデータ</span>
          <div class="input-box">
            <el-input v-model="reportData" :readonly="!isReportEditing" class="full-width-input"></el-input>
            <el-button type="success" @click="toggleEdit('i1')">編集</el-button>
            <el-button type="primary" @click="save('i1')">保存</el-button>
          </div>
        </div> -->

        <div class="input-group">
          <span class="label">レポートデータ</span>
            <div class="input-box">
              <el-input
                v-model="reportData"
                :disabled="!isEditing_reportData"
                class="full-width-input"
              ></el-input>
              <el-button type="primary" @click="toggleEdit1">
                {{ isEditing_reportData ? '保存' : '編集' }}
              </el-button>
            </div>
        </div>

        <div class="input-group">
          <span class="label">共通コメントファイル</span>
            <div class="input-box">
                <el-input
                  v-model="commonComment"
                  :disabled="!isEditing_commonComment"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit2">
                  {{ isEditing_commonComment ? '保存' : '編集' }}
                </el-button>
              </div>
        </div>

        <div class="input-group">
          <span class="label">個別コメントファイル</span>
            <div class="input-box">
                <el-input
                  v-model="individualComment"
                  :disabled="!isEditing_individualComment"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit3">
                  {{ isEditing_individualComment ? '保存' : '編集' }}
                </el-button>
            </div>
        </div>
        <!-- <div class="input-group">
          <span class="label">10銘柄マスター管理表</span>
          <div class="input-box">
                <el-input
                  v-model="meigara"
                  :disabled="!isEditing_meigara"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit4">
                  {{ isEditing_meigara ? '保存' : '編集' }}
                </el-button>
            </div>
        </div> -->
        <div class="input-group">
          <span class="label">銘柄マスター管理表更新用ファイル</span>
          <div class="input-box">
                <el-input
                  v-model="meigaramaster"
                  :disabled="!isEditing_meigaramaster"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit5">
                  {{ isEditing_meigaramaster ? '保存' : '編集' }}
                </el-button>
            </div>
        </div>
        <div class="input-group" v-if="fundType === '私募'">
          <span class="label">私募コメントとファンド管理表</span>

          <div class="input-box">
                <el-input
                  v-model="simu"
                  :disabled="!isEditing_simu"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit6">
                  {{ isEditing_simu ? '保存' : '編集' }}
                </el-button>
            </div>
        </div>

        <!-- 左侧底部管理按钮 -->
        <div class="bottom-left-buttons">
          <el-button type="default"  @click="openProxyDialog">Proxyアカウント管理</el-button>
          <!-- <el-button type="default" @click="openServerDialog">サーバーアカウント管理</el-button> -->
        </div>
      </div>

      <!-- 右侧（アウトプットパス指定） -->
      <div class="right-section">
        <h3>アウトプットパス指定</h3>
        <!-- 個別コメントファイル -->
        <div class="output-box">
          <h4>個別コメントファイル</h4>
          <div class="input-group">
            <span class="label">不一致修正後EXCEL保存パス</span>

            <div class="input-box">
                <el-input
                  v-model="individualExcelPath"
                  :disabled="!isEditing_individualExcelPath"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit7">
                  {{ isEditing_individualExcelPath ? '保存' : '編集' }}
                </el-button>
            </div>
          </div>
          <div class="input-group">
            <span class="label">修正後EXCEL PDF転換保存パス</span>

            <div class="input-box">
                <el-input
                  v-model="individualPdfPath"
                  :disabled="!isEditing_individualPdfPath"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit8">
                  {{ isEditing_individualPdfPath ? '保存' : '編集' }}
                </el-button>
            </div>
          </div>
          <div class="input-group">
            <span class="label">{{ fundType }}チェック結果保存パス</span>

            <div class="input-box">
                <el-input
                  v-model="individualCheckPath"
                  :disabled="!isEditing_individualCheckPath"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit9">
                  {{ isEditing_individualCheckPath ? '保存' : '編集' }}
                </el-button>
            </div>
          </div>
          <div class="input-group" v-if="fundType === '私募'">
            <span class="label">問題なしコメントファイル移動先</span>

            <div class="input-box">
                <el-input
                  v-model="resultngPath"
                  :disabled="!isEditing_resultngPath"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit10">
                  {{ isEditing_resultngPath ? '保存' : '編集' }}
                </el-button>
            </div>
          </div>
          <div class="input-group" v-if="fundType === '私募'">
            <span class="label">問題ありコメントファイル移動先</span>

            <div class="input-box">
                <el-input
                  v-model="resultokPath"
                  :disabled="!isEditing_resultokPath"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit11">
                  {{ isEditing_resultokPath ? '保存' : '編集' }}
                </el-button>
            </div>
          </div>

          <div class="input-group" v-if="fundType === '私募'">
            <span class="label">10銘柄マスタ管理表保存パス</span>

            <div class="input-box">
                <el-input
                  v-model="tenmanagePath"
                  :disabled="!isEditing_tenmanagePath"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit12">
                  {{ isEditing_tenmanagePath ? '保存' : '編集' }}
                </el-button>
            </div>
          </div>

          <div class="input-group" v-if="fundType === '私募'">
            <span class="label">ログ保存パス</span>

            <div class="input-box">
                <el-input
                  v-model="logsavePath"
                  :disabled="!isEditing_logsavePath"
                  class="full-width-input"
                ></el-input>
                <el-button type="primary" @click="toggleEdit13">
                  {{ isEditing_logsavePath ? '保存' : '編集' }}
                </el-button>
            </div>
          </div>

        </div>
      </div>
    </div>
    <span slot="footer" class="dialog-footer">
      <el-button type="primary" @click="handleConfirm">確認</el-button>
      <el-button @click="handleClose">閉じる</el-button>
    </span>

    <!-- Proxy 账户管理弹窗 -->
    <el-dialog
      title="Proxyアカウント管理"
      :visible.sync="proxyDialogVisible"
      width="40%"
      append-to-body
      :modal="false"
      @close="proxyDialogVisible = false"
      @open="fetchProxyAccount"
    >
      <div>
        <label>ユーザー名</label>
        <el-input v-model="proxyUsername" placeholder="ユーザー名を入力してください"></el-input>
        
        <label>パスワード</label>
        <el-input v-model="proxyPassword" placeholder="パスワードを入力してください" show-password></el-input>
      </div>

      <span slot="footer" class="dialog-footer">
        <el-button type="primary" @click="handleSaveProxyAccount">保存</el-button>
        <el-button @click="proxyDialogVisible = false">閉じる</el-button>
      </span>
    </el-dialog>
    <el-dialog
      title="サーバーアカウント管理"
      :visible.sync="serverDialogVisible"
      width="40%"
      append-to-body
      :modal="false"
      @open="fetchServerAccount"
      @close="serverDialogVisible = false"
    >
      <el-form>
        <el-form-item label="ユーザー名">
          <el-input v-model="serverUsername" placeholder="ユーザー名を入力してください"></el-input>
        </el-form-item>

        <el-form-item label="パスワード">
          <el-input v-model="serverPassword" type="password" placeholder="パスワードを入力してください"></el-input>
        </el-form-item>
      </el-form>

      <span slot="footer" class="dialog-footer">
        <el-button type="primary" @click="handleSaveServerAccount">保存</el-button>
        <el-button @click="serverDialogVisible = false">閉じる</el-button>
      </span>
    </el-dialog>


    <!-- 隐藏的文件选择器 -->
    <input ref="fileInput" type="file" webkitdirectory style="display: none" @change="handlePathChange" />
  </el-dialog>
</template>

<script>
import { getProxyAccount, saveProxyAccount, getServerAccount, saveServerAccount, getPaths, savePaths } from "@/api/proxy";

export default {
  name: "PathPopup",
  props: {
    visible: {
      type: Boolean,
      required: true,
    },
  },
  data() {
    return {
      isEditing_reportData: false,
      isEditing_commonComment: false,
      isEditing_individualComment: false,
      isEditing_meigara: false,
      isEditing_meigaramaster: false,
      isEditing_simu: false,
      isEditing_individualExcelPath: false,
      isEditing_individualPdfPath: false,
      isEditing_individualCheckPath: false,
      isEditing_resultngPath: false,
      isEditing_resultokPath: false,
      isEditing_tenmanagePath: false,
      isEditing_logsavePath: false,
      reportData: "",
      commonComment: "",
      individualComment: "",
      meigara:"",
      individualExcelPath: "",
      individualPdfPath: "",
      currentTarget: "", // 记录当前选择的路径字段
      individualCheckPath: "",
      resultngPath: "",
      resultokPath: "",
      tenmanagePath: "",
      logsavePath: "",
      simu: "",
      meigaramaster: "",
      isReportEditing: false,
      proxyDialogVisible: false, // ✅ Proxy 账户管理弹窗的控制
      proxyUsername: "",
      proxyPassword: "",
      serverDialogVisible: false,  // ✅ 服务器账户弹窗
      serverUsername: "",
      serverPassword: "",
      fundType: "", 
      data:[],
      originalValues: {},  // <-- 원래 값 저장용
      localVisible: this.visible,


    };
  },
  mounted() {
    this.fundType = this.$route.query.fundType || "公募"; // 默认是公募
  },
  watch: {
    visible(newVal) {
    this.localVisible = newVal;
    if (newVal) {
      this.fetchPaths();
    }
  },
  localVisible(newVal) {
    this.$emit('update:visible', newVal);
  }
  },
  methods: {
    toggleEdit1() {
    this.isEditing_reportData = !this.isEditing_reportData;
  },
    toggleEdit2() {
    this.isEditing_commonComment = !this.isEditing_commonComment;
  },
    toggleEdit3() {
    this.isEditing_individualComment = !this.isEditing_individualComment;
  },
    toggleEdit4() {
    this.isEditing_meigara = !this.isEditing_meigara;
  },
    toggleEdit5() {
    this.isEditing_meigaramaster = !this.isEditing_meigaramaster;
  },
    toggleEdit6() {
    this.isEditing_simu = !this.isEditing_simu;

  },
    toggleEdit7() {
    this.isEditing_individualExcelPath = !this.isEditing_individualExcelPath;
  },
    toggleEdit8() {
    this.isEditing_individualPdfPath = !this.isEditing_individualPdfPath;
  },
    toggleEdit9() {
    this.isEditing_individualCheckPath = !this.isEditing_individualCheckPath;
  },
    toggleEdit10() {
    this.isEditing_resultngPath = !this.isEditing_resultngPath;
  },
    toggleEdit11() {
    this.isEditing_resultokPath = !this.isEditing_resultokPath;
  },
    toggleEdit12() {
    this.isEditing_tenmanagePath = !this.isEditing_tenmanagePath;
  },
    toggleEdit13() {
    this.isEditing_logsavePath = !this.isEditing_logsavePath;
  },
    // ✅ 发送 Proxy 账户数据到后端
    async fetchProxyAccount() {
      const response = await getProxyAccount();
      if (response.code === 200) {
        this.proxyUsername = response.data[0].username;
        this.proxyPassword = response.data[0].password;
      } else {
        this.$message.error("アカウント情報の取得に失敗しました");
      }
    },
    // ✅ 保存 Proxy 账户信息
    async handleSaveProxyAccount() {
      if (!this.proxyUsername || !this.proxyPassword) {
        this.$message.error("ユーザー名とパスワードを入力してください");
        return;
      }

      const response = await saveProxyAccount(this.proxyUsername, this.proxyPassword);
      if (response.code === 200) {
        this.$message.success("アカウントが保存されました");
        this.proxyDialogVisible = false;
      } else {
        this.$message.error("アカウントの保存に失敗しました");
      }
    },
    async selectPath(target) {
      try {
        const response = await fetch("http://127.0.0.1:5000/api/select-folder", {
          method: "GET",
          headers: {
            "Content-Type": "application/json",
          },
        });

        if (!response.ok) throw new Error("HTTP error " + response.status);

        const data = await response.json();
        if (data.path) {
          this[target] = data.path;
        } else {
          this.$message.error("フォルダが選択されていません");
        }
      } catch (error) {
        console.error("フォルダ選択エラー:", error);
        this.$message.error("フォルダ選択に失敗しました");
      }
    },
    handlePathChange(event) {
      const files = event.target.files;
      if (files.length > 0) {
        // 选取第一个文件的路径
        const filePath = files[0].webkitRelativePath || files[0].name;
        // 提取文件夹路径（去掉文件名）
        const folderPath = filePath.substring(0, filePath.lastIndexOf("/"));
        // 将路径填充到对应的输入框
        this[this.currentTarget] = folderPath;
      }
      this.$refs.fileInput.value = ""; // 清空 input，确保可以重复选择
    },

    handleClose() {
      this.$emit("update:visible", false);
      this.isEditing_reportData =  false;
      this.isEditing_commonComment =  false;
      this.isEditing_individualComment =  false;
      this.isEditing_meigara =  false;
      this.isEditing_meigaramaster =  false;
      this.isEditing_simu =  false;
      this.isEditing_individualExcelPath =  false;
      this.isEditing_individualPdfPath =  false;
      this.isEditing_individualCheckPath =  false;
      this.isEditing_resultngPath = false;
      this.isEditing_resultokPath = false;
      this.isEditing_tenmanagePath = false;
      this.isEditing_logsavePath = false;
    },
    // ✅ 打开 Proxy 账户管理弹窗
    openProxyDialog() {
      this.proxyDialogVisible = true;
    },
    // ✅ 打开 服务器账户管理 弹窗，并获取服务器账户数据
  async openServerDialog() {
    this.serverDialogVisible = true;
    await this.fetchServerAccount();  // 获取服务器账户信息
  },

  // ✅ 获取 服务器账户信息 , TODO ,需要考虑多个用户
  async fetchServerAccount() {
    try {
      const response = await getServerAccount();
      if (response.code === 200) {
        this.serverUsername = response.data[0].username;
        this.serverPassword = response.data[0].password;
      } else {
        this.$message.error("サーバーアカウントの取得に失敗しました");
      }
    } catch (error) {
      console.error("サーバーアカウント取得エラー:", error);
      this.$message.error("サーバーアカウントの取得に失敗しました");
    }
  },

  // ✅ 保存 服务器账户信息
  async handleSaveServerAccount() {
    if (!this.serverUsername || !this.serverPassword) {
      this.$message.error("ユーザー名とパスワードを入力してください");
      return;
    }

    try {
      const response = await saveServerAccount(this.serverUsername, this.serverPassword);
      if (response.code === 200) {
        this.$message.success("サーバーアカウントが保存されました");
        this.serverDialogVisible = false;
      } else {
        this.$message.error("サーバーアカウントの保存に失敗しました");
      }
    } catch (error) {
      console.error("サーバーアカウント保存エラー:", error);
      this.$message.error("サーバーアカウントの保存に失敗しました");
    }
  },
      // ✅ 获取路径数据
  async fetchPaths() {
      try {
        const data = await getPaths();
        const commont_data = data.data.filter(item => item.fund_type === this.fundType)
        this.reportData = commont_data[0].reportData || "";
        this.commonComment = commont_data[0].commonComment || "";
        this.meigaramaster = commont_data[0].meigaramaster || "";
        this.simu = commont_data[0].simu || "";
        this.individualComment = commont_data[0].individualComment || "";
        this.individualExcelPath = commont_data[0].individualExcelPath || "";
        this.individualPdfPath = commont_data[0].individualPdfPath || "";
        this.individualCheckPath = commont_data[0].individualCheckPath || "";
        this.resultngPath = commont_data[0].resultngPath || "";
        this.resultokPath = commont_data[0].resultokPath || "";
        this.tenmanagePath = commont_data[0].tenmanagePath || "";
        this.logsavePath = commont_data[0].logsavePath || "";
        this.originalValues = {
          reportData: this.reportData,
          commonComment: this.commonComment,
          individualComment: this.individualComment,
          meigara: this.meigara,
          meigaramaster: this.meigaramaster,
          simu: this.simu,
          individualExcelPath: this.individualExcelPath,
          individualPdfPath: this.individualPdfPath,
          individualCheckPath: this.individualCheckPath,
          resultngPath: this.resultngPath,
          resultokPath: this.resultokPath,
          tenmanagePath: this.tenmanagePath,
          logsavePath: this.logsavePath
        };
      } catch (error) {
        // this.$message.error("getPaths データ取得に失敗しました");
      }
    },

    // ✅ 保存路径数据
  // async handleConfirm() {
  //     try {
  //       const payload = {
  //         reportData: this.reportData,
  //         commonComment: this.commonComment,
  //         individualComment: this.individualComment,
  //         meigara: this.meigara,
  //         meigaramaster: this.meigaramaster,
  //         simu: this.simu,
  //         individualExcelPath: this.individualExcelPath,
  //         individualPdfPath: this.individualPdfPath,
  //         individualCheckPath: this.individualCheckPath,
  //       };

  //       await savePaths(payload);
  //       this.$message.success("データが保存されました");
  //       this.handleClose();
  //     } catch (error) {
  //       this.$message.error("データの保存に失敗しました");
  //     }
  //   },
  
  // 只保存变更的路径
  async handleConfirm() {
  try {
    if (![
      this.isEditing_reportData, 
      this.isEditing_commonComment, 
      this.isEditing_individualComment, 
      this.isEditing_meigara, 
      this.isEditing_meigaramaster, 
      this.isEditing_simu, 
      this.isEditing_individualExcelPath, 
      this.isEditing_individualPdfPath, 
      this.isEditing_individualCheckPath, 
      this.isEditing_resultngPath, 
      this.isEditing_resultokPath,
      this.isEditing_tenmanagePath,
      this.isEditing_logsavePath].every(val => !val)) {
      this.$message.info("未保存の住所があります。保存してください。");
      return;
    } 

    const payload = {};

    for (const key in this.originalValues) {
      if (this[key] !== this.originalValues[key]) {
        payload[key] = this[key];
      }
    }

    if (Object.keys(payload).length === 0) {
      this.$message.info("変更はありません");
      return;
    }

    payload['fund_type'] = this.fundType;
    await savePaths(payload);
    this.$message.success("データが保存されました");

    // 저장 후 현재 상태를 다시 원본으로 저장
    this.originalValues = { ...this.originalValues, ...payload };

    this.handleClose();
  } catch (error) {
    this.$message.error("データの保存に失敗しました");
  }
}

  },
};
</script>

<style scoped>
.container {
  display: flex;
  justify-content: space-between;
  gap: 15px; /* 间距缩小 */
}

.left-section, .right-section {
  flex: 1;
  padding: 15px; /* 缩小内边距 */
  border: 1px solid #ccc;
  border-radius: 5px;
  background-color: #f9f9f9;
}

h3 {
  font-size: 16px; /* 标题字体变小 */
  border-bottom: 1px solid #ccc;
  padding-bottom: 3px;
  margin-bottom: 8px; /* 间距减少 */
}

.input-group {
  display: flex;
  flex-direction: column;
  margin-bottom: 10px; /* 组之间的间距减少 */
}

.label {
  font-weight: bold;
  margin-bottom: 3px;
}

.input-box {
  display: flex;
  align-items: center;
}

.input-box .el-input {
  flex: 1;
  margin-right: 8px;
}

.output-box {
  background-color: #fff;
  padding: 8px; /* 缩小 padding */
  border: 1px solid #ccc;
  border-radius: 5px;
  margin-bottom: 10px; /* 组之间的间距减少 */
}

h4 {
  font-size: 14px;
  margin-bottom: 6px;
}

.bottom-left-buttons {
  display: flex;
  justify-content: flex-start;
  gap: 8px; /* 按钮间距缩小 */
  margin-top: 15px; /* 底部按钮上方间距减少 */
}

.dialog-footer {
  display: flex;
  justify-content: flex-end;
  padding-top: 8px;
  margin-bottom: 5px; /* 底部间距减少 */
}
</style>
