<template>
  <el-dialog
    title="チェック結果"
    :visible.sync="visible"
    width="60%"
    @close="handleClose"
  >
    <div class="check-result-container">
      <el-table :data="tableData" border style="width: 100%">
        <el-table-column prop="no" label="No" width="60" align="center" />
        <el-table-column prop="pageNumber" label="ページ番号" width="150" align="center" />
        <el-table-column prop="checkItem" label="チェック項目" width="150" align="center" />
        <el-table-column prop="checkResult" label="チェック結果" width="150" align="center">
          <template slot-scope="scope">
            <span
              :class="{
                'result-error': scope.row.checkResult === '不一致',
                'result-success': scope.row.checkResult === '完全一致',
                'result-manual': scope.row.checkResult === '人工確認',
              }"
            >
              {{ scope.row.checkResult }}
            </span>
          </template>
        </el-table-column>
        <el-table-column prop="detail" label="不一致情報">
          <template slot-scope="scope">
            <div v-html="scope.row.detail"></div>
          </template>
        </el-table-column>
      </el-table>
    </div>
    <span slot="footer" class="dialog-footer">
      <el-button @click="handleClose">閉じる</el-button>
    </span>
  </el-dialog>
</template>

<script>
export default {
  name: "CheckResultPopup",
  props: {
    visible: Boolean,
    tableData: Array, // ✅ 直接从父组件接收数据
  },
  methods: {
    handleClose() {
      this.$emit("update:visible", false);
    },
  },
};
</script>

<style scoped>
.check-result-container {
  padding: 10px 0;
}

.result-error {
  color: red;
  font-weight: bold;
}

.result-success {
  color: green;
  font-weight: bold;
}

.result-manual {
  color: orange;
  font-weight: bold;
}

.el-table th {
  background-color: #f5f7fa;
  text-align: center;
}

.el-table td {
  text-align: center;
  white-space: pre-wrap;
}
</style>
