import Vue from 'vue'
import VueI18n from 'vue-i18n'
import en from './locales/en.json'
import zh from './locales/zh.json'
import ja from './locales/ja.json'

Vue.use(VueI18n)

const messages = {
  en,
  zh,
  ja
}

const i18n = new VueI18n({
  locale: 'ja', // 设置默认语言
  messages
})

export default i18n
