<template>
  <div class="file-preview">
    <!-- 对照模式 -->
    <div v-if="selectedMode === 'mode3'" class="comparison-mode">
      <div class="comparison-pane">
        <h3>原文</h3>
        <vue-office-docx
          v-if="fileType === 'docx' || fileType === 'doc'"
          :src="fileUrl"
          style="height: 100vh;"
          @rendered="onRendered"
          @error="onError"
        />
        <vue-office-excel
          v-if="fileType === 'xlsx' || fileType === 'xls'"
          :src="fileUrl"
          style="height: 100vh;"
          @rendered="onRendered"
          @error="onError"
        />
      </div>
      <div class="comparison-pane">
        <h3>対照モード</h3>
        <vue-office-docx
          v-if="fileType === 'docx' || fileType === 'doc'"
          :src="modifiedFileUrl"
          style="height: 100vh;"
          @rendered="onRendered"
          @error="onError"
        />
        <vue-office-excel
          v-if="fileType === 'xlsx' || fileType === 'xls'"
          :src="modifiedFileUrl"
          style="height: 100vh;"
          @rendered="onRendered"
          @error="onError"
        />
      </div>
    </div>

    <!-- 单文档模式 -->
    <div v-else-if="selectedMode === 'mode2'" class="single-pane-with-sidebar">
      <div class="document-pane">
        <vue-office-docx
          v-if="fileType === 'docx' || fileType === 'doc'"
          :src="activeFileUrl"
          style="height: 100vh;"
          @rendered="onRendered"
          @error="onError"
        />
        <vue-office-excel
          v-if="fileType === 'xlsx' || fileType === 'xls'"
          :src="activeFileUrl"
          style="height: 100vh;"
          @rendered="onRendered"
          @error="onError"
        />
      </div>
      <div class="sidebar">
        <h3>チェック結果</h3>
        <el-scrollbar style="height: 100%;">
          <ul>
            <li
              v-for="(item, index) in checkResults"
              :key="index"
              class="check-item"
            >
              <strong class="check-label">
                検出点{{ index + 1 }}：
                <span class="highlight-label">{{ item.label }}</span>
              </strong>
              <p class="check-details">
                詳細：
                <span class="highlight-details">{{ item.details }}</span>
              </p>
            </li>
          </ul>
          
        </el-scrollbar>
      </div>
    </div>

    <!-- 单文档模式 -->
    <div v-else>
      <vue-office-docx
        v-if="fileType === 'docx' || fileType === 'doc'"
        :src="activeFileUrl"
        style="height: 100vh;"
        @rendered="onRendered"
        @error="onError"
      />
      <vue-office-excel
        v-if="fileType === 'xlsx' || fileType === 'xls'"
        :src="activeFileUrl"
        style="height: 100vh;"
        @rendered="onRendered"
        @error="onError"
      />
      <div v-if="!loading && !['docx', 'doc', 'xlsx', 'xls'].includes(fileType)">
        サポートされていないファイル形式
      </div>
    </div>
  </div>
</template>

<script>
import VueOfficeDocx from "@vue-office/docx";
import VueOfficeExcel from "@vue-office/excel";
import "@vue-office/docx/lib/index.css";
import "@vue-office/excel/lib/index.css";

export default {
  components: { VueOfficeDocx, VueOfficeExcel },
  props: {
    fileName: {
      type: String,
      required: true,
    },
    selectedMode: {
      type: String,
      required: true,
    },
  },
  data() {
    return {
      loading: false,
      fileType: "",
      checkResults: [
        { label: "エル・ピ", details: "ここに問題がいである" },
        { label: "マンスリーアップデート", details: "ここに問題がいである" },
        { label: "グローバル", details: "ここに問題がいである" },
        { label: "与し", details: "ここに問題がいである" },
        { label: "7%", details: "ここに問題がいである" },
      ],
    };
  },
  computed: {
    fileUrl() {
      return `/files/${this.fileName}`;
    },
    modifiedFileUrl() {
      if (this.fileName) {
        const extensionIndex = this.fileName.lastIndexOf(".");
        if (extensionIndex !== -1) {
          return `/files/${this.fileName.substring(0, extensionIndex)}_1${this.fileName.substring(extensionIndex)}`;
        }
        return `/files/${this.fileName}_1`;
      }
      return "";
    },
    activeFileUrl() {
      if (this.selectedMode === "mode2") {
        return this.fileUrl.replace(/(\.[^.]+)$/, '_2$1'); // 替换为 _2 后缀的文档
      }
      return this.fileUrl;
    },
  },
  watch: {
    fileName: {
      immediate: true,
      handler(newFileName) {
        if (newFileName) {
          this.loadFile(newFileName);
        }
      },
    },
    selectedMode: {
      immediate: true,
      handler() {
        this.loadFile(this.fileName);
      },
    },
  },
  methods: {
    loadFile(fileName) {
      this.loading = true;
      const extension = fileName.split(".").pop().toLowerCase();
      if (["docx", "doc"].includes(extension)) {
        this.fileType = "docx";
      } else if (["xlsx", "xls"].includes(extension)) {
        this.fileType = "xlsx";
      } else {
        this.fileType = "";
      }
      this.loading = false;
    },
    onRendered() {
      console.log("文档渲染完成");
    },
    onError(error) {
      console.error("文档渲染失败", error);
    },
  },
};
</script>

<style scoped>
.file-preview {
  display: flex;
  flex-direction: column;
  height: 100vh;
}

.comparison-mode {
  display: flex;
  justify-content: space-between;
  flex: 1;
}

.comparison-pane {
  width: 48%;
  border: 1px solid #ddd;
  padding: 10px;
  background-color: #fff;
}

.single-pane-with-sidebar {
  display: flex;
  flex: 1;
}

.document-pane {
  flex: 2;
  border-right: 1px solid #ddd;
}

.sidebar {
  flex: 1;
  padding: 10px;
  background-color: #f5f5f5;
  overflow-y: auto;
}

.check-item {
  margin-bottom: 10px;
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 5px;
  background-color: #fff;
}
.check-label {
  color: #333;
  font-weight: bold;
}

.highlight-label {
  background-color: #ffeb3b; /* 黄色背景 */
  color: #d32f2f; /* 深红色字体 */
  padding: 2px 4px;
  border-radius: 3px;
}

.check-details {
  color: #666;
}

.highlight-details {
  background-color: #e0f7fa; /* 浅蓝色背景 */
  color: #00796b; /* 深绿色字体 */
  padding: 2px 4px;
  border-radius: 3px;
}

</style>
