<template>
  <div class="login-container">
    <div class="login-box">
      <div class="login-content">
        <div class="logo-title">
          <img src="/assets/logo_01.png" alt="Logo Image" />
        </div>
        <h2>ログイン</h2>
        <el-form :model="loginForm" ref="loginForm" class="login-form" @submit.native.prevent="handleLogin">
          <el-form-item prop="username">
            <el-input v-model="loginForm.username" placeholder="ユーザー名">
              <template #prefix>
                <i class="el-icon-user"></i>
              </template>
            </el-input>
          </el-form-item>
          <el-form-item prop="password">
            <el-input type="password" v-model="loginForm.password" show-password placeholder="パスワード">
              <template #prefix>
                <i class="el-icon-lock"></i>
              </template>
            </el-input>
          </el-form-item>
          <el-form-item class="checkbox-and-button">
            <el-checkbox v-model="loginForm.rememberMe" class="remember-me">パスワードを保存</el-checkbox>
          </el-form-item>
          <el-form-item>
            <el-button type="primary" class="login-button" @click="handleLogin" :loading="loading">ログイン</el-button>
          </el-form-item>
        </el-form>
      </div>
    </div>
  </div>
</template>

<script>
import { login } from "@/api/login.js";
import { Message } from "element-ui";

export default {
  name: "Login",
  data() {
    return {
      loginForm: {
        username: "",
        password: "",
        rememberMe: false,
      },
      loading: false,
    };
  },
  mounted() {
    console.log("🚀 组件加载，尝试读取本地存储...");
    this.loadSavedCredentials(); // 🔥 页面加载时读取本地存储
  },
  methods: {
    async handleLogin() {
      console.log("🚀 開始调用 API...");
      this.loading = true;

      try {
        const response = await login(this.loginForm.username, this.loginForm.password);
        console.log("✅ API 返回数据：", response);
        
        if (response.success =='true') {
          // ✅ **存储用户名 & 密码**
          if (this.loginForm.rememberMe) {
            localStorage.setItem("savedUsername", this.loginForm.username);
            localStorage.setItem("savedPassword", this.loginForm.password);
            localStorage.setItem("rememberMe", "true");
          } else {
            localStorage.removeItem("savedUsername");
            localStorage.removeItem("savedPassword");
            localStorage.removeItem("rememberMe");
          }

          // ✅ **存储 Token**
          localStorage.setItem("token", response.token);

          // ✅ **跳转页面**
          setTimeout(() => {
            this.$router.push({ path: "/Mainhome" });
          }, 10);

        } else {
          Message({
            message: response.message || "ログイン失敗！",
            type: "error",
            duration: 3000,
          });
        }
      } catch (error) {
        console.error("❌ 登录 API 调用失败", error);
        // 에러 메시지 출력
        if (error.response) {
          // 서버가 응답을 했지만 상태 코드가 2xx가 아닐 때
          this.$message.error(`エラー: ${error.response.data.message || 'ネットワークエラー'}`);
        } else if (error.request) {
          // 요청이 이루어졌지만 응답이 없을 때
          this.$message.error("サーバーからの応答がありません。");
        } else {
          // 다른 에러
          this.$message.error(`エラー: ${error.message}`);
        }
      } finally {
        this.loading = false;
      }
    },

    // ✅ **从 localStorage 读取用户名 & 密码**
  loadSavedCredentials() {
      const savedUsername = localStorage.getItem("savedUsername");
      const savedPassword = localStorage.getItem("savedPassword");
      const rememberMe = localStorage.getItem("rememberMe");

      // console.log("🔍 读取的本地存储:", { savedUsername, savedPassword, rememberMe });

      if (rememberMe === "true" && savedUsername && savedPassword) {
        this.loginForm.username = savedUsername;
        this.loginForm.password = savedPassword;
        this.loginForm.rememberMe = true;
        // console.log("✅ 自动填充用户名 & 密码");
      }
    },
  },
};
</script>

<style scoped>
.login-container {
  width: 100vw;
  height: 100vh;
  background-color: #e6ecf3; /* ✅ 柔和蓝灰色背景，更加正式 */
  display: flex;
  justify-content: center;
  align-items: center;
  font-family: 'Segoe UI', 'Helvetica Neue', Helvetica, Arial, sans-serif;
}


/* ===== 登录框样式 ===== */
.login-box {
  width: 400px;
  padding: 40px 30px;
  background: #fff;
  border-radius: 10px;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08);
  text-align: center;
}

/* ===== LOGO ===== */
.logo-title img {
  width: 300px;
  margin-bottom: 20px;
}

/* ===== 标题 ===== */
h2 {
  color: #333;
  font-weight: 600;
  font-size: 22px;
  margin-bottom: 25px;
}

/* ===== 表单样式 ===== */
.login-form {
  width: 100%;
  text-align: left;
}

/* ===== 输入框样式重置 ===== */
.el-input__inner {
  border: 1px solid #dcdfe6;
  border-radius: 6px;
  background-color: #f5f7fa;
  color: #303133;
  padding-left: 36px !important;
  height: 38px;
  box-shadow: none !important;
}

/* 去除输入框中 inset 阴影框 */
.el-input__inner:focus {
  border-color: #409EFF;
  background-color: #ffffff;
}

/* 图标对齐 */
.el-input__prefix {
  display: flex;
  align-items: center;
  height: 100%;
  left: 8px;
}

.el-input__prefix .el-icon-user,
.el-input__prefix .el-icon-lock {
  font-size: 16px;
  color: #909399;
}

/* 记住密码 */
.remember-me {
  color: #606266;
  font-size: 14px;
}

/* 登录按钮 */
.login-button {
  width: 100%;
  padding: 12px;
  font-size: 16px;
  border-radius: 6px;
  background-color: #409EFF;
  border: none;
  color: white;
  transition: background-color 0.3s;
}

.login-button:hover {
  background-color: #66b1ff;
}


</style>
