<template>
  <div class="check-fund-detail">
    <!-- 左侧内容区域：PDF或Excel展示 -->
    <!-- 左侧 PDF 预览区域 -->
    <div v-if="isPDF" class="pdf-preview">
      <div class="pdf-controls">
        <el-button @click="prevPage" :disabled="currentPage === 1">前のページ</el-button>
        <span>第 {{ currentPage }} ページ / 合計 {{ totalPages }} ページ</span>
        <el-button @click="nextPage" :disabled="currentPage >= totalPages">次のページ</el-button>
      </div>
      <canvas id="pdf-canvas" ref="pdfCanvas"></canvas>
    </div>

    <!-- 右侧「チェック結果」区域 -->
    <div  v-if="shouldShowCheckResults" class="check-result-aside">
      <div class="check-result-header">
        <h3>チェック結果 ({{ resultGroups.flatMap(group => group.items).length }}個) - {{ selectedFile }}</h3>
      </div>
      <el-collapse v-model="activeResultGroups" class="check-result-groups">
        <el-collapse-item
          v-for="(group, groupIndex) in resultGroups"
          :key="groupIndex"
          :title="group.title"
        >
          <div
            v-for="(item, itemIndex) in group.items"
            :key="itemIndex"
            class="result-item"
            @mouseenter="highlightCheckPoint(item)"
            @mouseleave="clearHighlight"
          >
          <p class="item-title">
            <strong>検出点 {{ itemIndex + 1 }}：</strong> {{ item.reason_type ==="" ? "正しい観点": item.reason_type }}
            <span v-if="item.fileUrl" class="file-link">
              <a :href="item.fileUrl" target="_blank" rel="noopener noreferrer">
                {{ item.fileName || "ファイルを開く" }}
              </a>
            </span>
          </p>
          
            <div class="item-details">
              <p
                v-for="(change, changeIndex) in item.changes"
                :key="changeIndex"
                class="change-detail"
              >
                <span
                  :class="[getHighlightClass(item.name, 'before',item.reason_type), needsStrikeThrough(item.name) ? 'with-strike' : '']"
                v-html="item.reason_type === '常用外漢字の使用' ? item.check_point : change.before">
                </span>
                <!-- <span class="arrow"> {{item.reason_type ==="" ? "": "➡" }} </span> -->
                <!-- item.reason_type이 "常用外漢字の使用"인 경우 화살표와 change.after 숨기기 -->
                <span v-if="item.reason_type !=='常用外漢字の使用' && item.reason_type !=='メッセージの表示' && item.reason_type !=='銘柄解説一致' && item.reason_type !=='整合性'" class="arrow">
                  {{ item.reason_type === "" ? "" : "➡" }}
                </span>
                <!-- <span :class="getHighlightClass(item.name, 'after')" v-html="change.after"></span> -->
                <span v-if="item.reason_type !=='常用外漢字の使用' && item.reason_type !=='メッセージの表示' && item.reason_type !=='銘柄解説一致' && item.reason_type !=='整合性'" :class="getHighlightClass(item.name, 'after',item.reason_type)" v-html="change.after"></span>
              </p>
            </div>
          </div>
        </el-collapse-item>
      </el-collapse>
    </div>
  </div>
</template>


<script>
import { getDocument, GlobalWorkerOptions } from "pdfjs-dist";
import pdfjsWorker from "pdfjs-dist/build/pdf.worker.entry";
import { getCheckResults } from "@/api/check"; // API 请求检查点数据
// import Vue from "vue";


export default {
  props: {
    selectedPdfPath: {
      type: String,
      required: true,
      default: "" // ✅ 기본값 설정 (빈 문자열)
    },
    selectedId: {
      type: String,
      required: true,
    },
    selectedFile: {
      type: String,
      required: true,
    },
    selectedFolder: {
      type: String,
      required: true,
    },
    fundType: { // fundType prop 추가
      type: String,
      default: '公募'
    },
    //  currentPage: {  // currentPage를 props로 정의
    //   type: Number,
    //   required: true,
    //   default: 1,
    // },
     totalPages: {  // totalPages를 props로 정의
      type: Number,
      required: true,
      // default: 1,
    },
  },
  data() {
    return {
      isPDF: false,
      errorMessage: "",
      activeResultGroups: [],
      pdfInstance: null, // PDF.js 实例
      pdfCanvasContext: null, // Canvas 上下文
      pdfViewport: null, // PDF 视口
      currentPage: 1, // 731 debug
      // totalPages: 1,
      resultGroups: [],
      selectedFundType: this.fundType, // props에서 초기값 설정
    };
  },
  computed: {
    totalCheckPoints() {
      return Array.isArray(this.resultGroups)
        ? this.resultGroups.reduce((sum, group) => sum + (group.items ? group.items.length : 0), 0)
        : 0;
    },
    shouldShowCheckResults() {
      return this.selectedFolder === "📂 共通コメントファイル" || this.selectedFolder === "📂 個別コメントファイル";
    },
  },
  watch: {
    fundType: {
      immediate: true,
      handler(newValue) {
        this.selectedFundType = newValue;
      }
    },
    selectedPdfPath: {
      immediate: true,
      handler(newPath) {
        if (newPath) {
          // console.log("📂 加载 PDF 文件:", newPath);
          this.loadPDF(newPath);
        }
      }
    },
    currentPage(newPage) { // ✅ 监听页码变化
      // console.log("🔄 切换到第", newPage, "页，刷新检查点");
      this.fetchCheckResults(this.selectedId, newPage);
    }
  },
  created() {
    this.selectedFundType = this.$route.query.fundType || '公募';
    this.selectedStatus = ""; // 默认显示全部
    this.$emit('totalPages', this.totalPages);
  },
  methods: {
  setupPDFJS() {
    GlobalWorkerOptions.workerSrc = pdfjsWorker;
  },
  async loadPDF(filePath) {      
      try {
        this.isPDF = true;
        this.setupPDFJS();
        // const filePath = "/files/180010-1_M2501.pdf";
        const loadingTask = getDocument({
          url: filePath,
          cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
          cMapPacked: true,
          disableFontFace: true, // disabale ,font error 
          verbosity: 1 // setting debug level
        });

        // 3. PDF load doc
        const pdf = await loadingTask.promise;
        
        this.pdfInstance = pdf;
        this.totalPages = pdf.numPages;
        this.currentPage = 1;
        await this.renderPage(this.currentPage);
        this.$emit('totalPages', this.totalPages);
      } catch (error) {
        this.isPDF = false;
        this.errorMessage = "PDF Loading error: " + error.message;
        console.error("❌ PDF Loading error is:", {
          name: error.name,
          message: error.message,
          stack: error.stack
        });
      }
    },


    async renderPage(pageNumber) {
      if (!this.pdfInstance) return;
      if (this.pdfCanvasContext) {
        this.pdfCanvasContext.clearRect(
          0, 0, 
          this.pdfCanvasContext.canvas.width, 
          this.pdfCanvasContext.canvas.height
        );
      }
      const canvas = this.$refs.pdfCanvas;
      if (!canvas) {
        console.error("❌ PDF Canvas is not defined");
        return;
      }

      const page = await this.pdfInstance.getPage(pageNumber);
      const context = canvas.getContext("2d");
      this.pdfCanvasContext = context;

      const viewport = page.getViewport({ scale: 1.5 });
      this.pdfViewport = viewport;

      canvas.height = viewport.height;
      canvas.width = viewport.width;

      await page.render({ canvasContext: context, viewport }).promise;
    },


  prevPage() {
    if (this.currentPage > 1) {
      this.currentPage--;
      this.renderPage(this.currentPage);
      // this.$emit('page-changed', this.currentPage);
      this.$emit('totalPages', this.totalPages);
    }
  },

  nextPage() {
    if (this.currentPage < this.totalPages) {
      this.currentPage++;
      this.renderPage(this.currentPage);
      // this.$emit('page-changed', this.currentPage);
      this.$emit('totalPages', this.totalPages);
    }
  },
  transformCheckData(inputData) {
  const checkData = {
    code: 200,
    message: "成功",
    data: []
  };



  for (const [id, entries] of Object.entries(inputData.data)) {
    // loop entries
    entries.forEach((entry) => {
      const transformedEntry = {
        title: entry.title, // add title
        items: [],
        id: id
      };

      // loop
      entry.items.forEach(item => {
          // positions 배열이 있으면 첫 번째 위치를 사용
        // const position = (item.positions && item.positions.length > 0) ? item.positions[0] : item.position;
        const transformedItem = {
          name: item.name, // for Green Title
          color: item.color,
          page: item.page,
          position: {
            x: item.position.x,
            y: item.position.y,
            width: item.position.width,
            height: item.position.height
          },
          changes: item.changes,
          reason_type:item.reason_type,
          check_point:item.check_point,
        };
        // positions 배열이 있는 경우, 각 위치마다 item 생성

        // add changed item
        transformedEntry.items.push(transformedItem);
      });

      // push data
      checkData.data.push(transformedEntry);
    });
  }

  return checkData; // return result
},
  sortItemsByPosition(items) {
    return items.sort((a, b) => {
      const rectA = a.position;
      const rectB = b.position;
      
      // 主排序：Y坐标（从上到下）
      if (rectA.y !== rectB.y) {
        return rectB.y - rectA.y; // Y值越大表示位置越高
      }
      // 次排序：X坐标（从左到右）
      return rectA.x - rectB.x;
    });
  },
  
  async fetchCheckResults(selectedId) { 
    if (!selectedId) return; // ID가 없으면 실행하지 않음
    try {
      const response = await getCheckResults(this.selectedId,this.currentPage,this.selectedFundType === '私募' ? 'private' : 'public');
      const res = this.transformCheckData(response)
      // console.log(res,'---res')
      // all before
      const filterWords = {
        "　「日本プロ": true,
        "　日本取引所": true,
        "　15日に東": true,
        "　日本経済は": true,
        "  (    ": true,
        " )　　 　": true,
        "　地方主要都": true,
        " )　　　　": true,
        "　相対的に利": true,
        "　ポートフォ": true,
        " 米国と中国": true,
        " 米国の債券": true,
        " ・・・ 景": true,
        " ・・・ ド": true,
        " ・・・ 日": true,
        " ・・・ F": true,
        " ・・・ 長": true,
        " ・・・ ガ": true,
        "　為替 ・・": true,
        " ＜月間の基": true,
        " 長め（地域": true,
        " 現在 )": true,
        " 2025年": true,
        " 愛称：3県": true,
        "　当ファンド": true,
        "　2024年": true,
        "　新たなデジ": true,
        "　直近では、": true,
        "　2025年": true,
        "  (2025": true,
        "現在）": true,
        " ( ": true,
        "現在　": true,
        "現在)": true,
        " 現在）": true,
        "１": true,
        "ＦＵＮＤＳ": true,
        "ＮＥＸＴ": true,
        "（適格機関": true,
        ")\n": true,
        "クスファンド\nファンドは、値": true,  // all before
        "#VALUE!\n野村": true,  // all before
        "）ので、基準価額は変動します。": true,  // all before
        // "（USD）": true,  // all before
      };
      // 确保数据是数组
      this.resultGroups = Array.isArray(res.data) ? res.data.map(group => ({
        ...group,
        items: group.items.map(item => {
          // changes가 존재하고, 배열의 길이가 1 이상일 때만 after와 before 값을 가져옴
          const changes = item.changes || [];
          if (changes.length > 0) {
            const afterChange = changes[0].after; // after 값
            const beforeChange = changes[0].before; // before 값

            // after와 before가 같으면 해당 item을 반환하지 않음
            if(item.reason_type !== '常用外漢字の使用' && item.reason_type !== "新規銘柄" && item.reason_type !== "不自然な空白"){
              if (afterChange === beforeChange) {
                return null; // null을 반환하여 필터링할 수 있도록 함
              }
            }

            if(item.reason_type && item.reason_type.includes("日付表記として不自然なため")){
              return null;
            }
            
            // if(item.reason_type && item.reason_type.includes("日付部分に不要なタイムスタンプ")){
            //   return null;
            // }
            // after가 before 안에 포함되어 있으면 null 반환
            // if (beforeChange.includes(item.reason_type)){
            //   return null;
            // }
            if (beforeChange === '先月の投資環境' || beforeChange === '先月の運用経過' 
                || beforeChange === '10' || beforeChange === '今後の運用方針') {
              return null; // null을 반환하여 필터링할 수 있도록 함
            }
            
            if (beforeChange ==="必ず") {
                return null; // null을 반환하여 필터링할 수 있도록 함
              }
            if (beforeChange ==="銘柄\n純資産比") {
                return null; // null을 반환하여 필터링할 수 있도록 함
              }
            if (beforeChange ==="会社（以下「ＪＰＸ」という。") {
                return null; // null을 반환하여 필터링할 수 있도록 함
              }
            if (beforeChange ==="（USD）") {
                return null; // null을 반환하여 필터링할 수 있도록 함
              }


              if (this.selectedFundType === '公募' && filterWords[beforeChange]) {
                return null;
              }
              if(afterChange.includes("現在")){
              return null;
            }
              if(afterChange.includes("詳しくは、")){
              return null;
            }
              if(afterChange.includes("（運用実績、分配金は、")){
              return null;
            }
              if(afterChange.includes("4月のJ-")){
              return null;
            }
              if(afterChange.includes("あります）。")){
              return null;
            }
              if(afterChange.includes("当ファンド")){
              return null;
            }
            const match_page = beforeChange.match(/^\d+\/\d/)
            if (match_page){
              if(beforeChange.includes(match_page)){
                          return null;
                        }
              }
            
          }

          // if (item.position.height === 0 && item.position.width === 0) {
          //     return null; // null을 반환하여 필터링할 수 있도록 함
          //   }

          if (this.selectedFundType === '私募' && item.position.height === 0 && item.reason_type !== "不自然な空白") {
              return null;
            }
          if (this.selectedFundType === '公募' && item.position.height === 0) {
              return null; 
            }
            // 729 bug fix
          if (this.selectedFundType === '公募' && item.reason_type == "不自然な空白") {
              return null; 
            }

          if (item.reason_type === "文末の括弧内に「。」が抜けていたため、文法的に正しい文とするために句点を追加。"
            || item.reason_type ===  "文末が文法的に完結しているにもかかわらず「。」が抜けていたため"
            || item.reason_type === "文末の完結した文に句点「。」が抜けているため"
          ) {
              return null; // null을 반환하여 필터링할 수 있도록 함
            }

          // item을 그대로 반환
          return {
            ...item,
            fileName: item.fileName || "",  // 确保 fileName 存在
            fileUrl: item.fileUrl || ""    // 确保 fileUrl 存在
          };
        }).filter(item => item !== null) // null 값을 필터링
      })) : [];

      this.resultGroups[0].items = this.sortItemsByPosition(this.resultGroups[0].items)
      // console.log("✅ 获取检查点数据成功:", this.resultGroups[0].items);
      
      // console.log("✅ 获取检查点数据成功:", this.resultGroups);
    } catch (error) {
      // console.error("❌ 获取检查点数据失败:", error);
      this.resultGroups = [];
    }
  },
highlightCheckPoint(item) {

  if (!this.pdfCanvasContext || !item.position) return;

  const { x, y, width, height } = item.position;

  // console.log("🎯 高亮检查点:", item);

  // Canvas 상태 저장
  this.pdfCanvasContext.save();

  // 현재 Canvas 상태를 저장 (이전 하이라이트를 지우기 위해)
  this.storedImageData = this.pdfCanvasContext.getImageData(0, 0, this.pdfViewport.width, this.pdfViewport.height);

  // 하이라이트 색상 설정
  this.pdfCanvasContext.fillStyle = item.color || "rgba(255, 0, 0, 0.5)";

  // 하이라이트 영역 그리기
  this.pdfCanvasContext.fillRect(
    x * this.pdfViewport.scale,
    this.pdfViewport.height - y * this.pdfViewport.scale - height * this.pdfViewport.scale,
    width * this.pdfViewport.scale+100,
    height * this.pdfViewport.scale
  );

  // Canvas 상태 복원
  this.pdfCanvasContext.restore();
},

clearHighlight() {
  if (!this.pdfCanvasContext || !this.pdfInstance || !this.storedImageData) return;

  console.log("🔄 清除高亮");

  // 이전 Canvas 상태로 복원
  this.pdfCanvasContext.putImageData(this.storedImageData, 0, 0);
}
,
  getHighlightClass(name, type, reason_type) {
      if (name === "不一致") {
        if (reason_type === "整合性") {
          return type === "before" ? "highlight-integrity-before-zhenghe" : "highlight-integrity-after";
        }
        
        return type === "before" ? "highlight-integrity-before" : "highlight-integrity-after";
      }

      if (reason_type === "新規銘柄") {
        return type === "before" ? "highlight-integrity-before-tenbrend-upgrate" : "highlight-after";
      }

      if (reason_type === "銘柄解説更新あり") {
        return type === "before" ? "highlight-integrity-before-tenbrend-upgrate" : "highlight-after-tenbrend-upgrate";
      }

      if (reason_type === "銘柄解説一致") {
        return type === "before" ? "highlight-integrity-before-tenbrend-upgrate" : "highlight-after-tenbrend-same";
      }

      return type === "before" ? "highlight-before" : "highlight-after";
    },
    needsStrikeThrough(name) {
      return name !== "不一致" ; // 如果不是 "整合性"，则需要删除线  return name !== "不一致"
    },
}

};
</script>

<style scoped>
/* 主体布局样式 */
.check-fund-detail {
  display: flex;
  height: 100%;
}

.pdf-preview {
  flex: 2;
  overflow: auto;
  padding: 10px;
}

.file-preview {
  flex: 2;
  overflow: auto;
  padding: 10px;
}

.check-result-aside {
  flex: 1;
  padding: 10px;
  background-color: #f9f9f9;
  border-left: 1px solid #ddd;
}

.check-result-header {
  font-size: 18px;
  font-weight: bold;
  margin-bottom: 10px;
}

.check-result-groups {
  max-height: 100%;
  overflow-y: auto;
}

.result-item {
  margin-bottom: 10px;
  padding: 10px;
  background: #ffffff;
  border: 1px solid #ddd;
  border-radius: 4px;
}

.item-title {
  font-weight: bold;
  margin-bottom: 5px;
}

.item-details {
  margin-left: 10px;
  line-height: 1.6;
}

/* 样式：删除线 + 背景 */
.with-strike {
  text-decoration: line-through; /* 删除线 */
}

/* 整合性的特殊样式 */
.highlight-integrity-before {
  background-color: #ace4e6;
  color: rgb(255, 0, 0);
  padding: 2px 4px;
  border-radius: 3px;
  font-weight: bold;
  text-decoration: line-through;
}
.highlight-integrity-before-zhenghe {
    background-color: #ace4e6;
    color: #303133;
    padding: 2px 4px;
    border-radius: 3px;
    font-weight: bold;
}

.highlight-integrity-after {
  /* background-color: lightgreen; */
  /* color: green; */
  padding: 2px 4px;
  border-radius: 3px;
  font-weight: bold;
}

/* 其他问题的默认样式 */
.highlight-before {
  background-color: yellow;
  color: red;
  padding: 2px 4px;
  border-radius: 3px;
  font-weight: bold;
}

.highlight-after {
  background-color: yellow;
  color: green;
  padding: 2px 4px;
  border-radius: 3px;
  font-weight: bold;
}


.highlight-integrity-before-tenbrend-upgrate {
  background-color: #ccc;
  color: rgb(255, 0, 0);
  padding: 2px 4px;
  border-radius: 3px;
  font-weight: bold;
  text-decoration: line-through;
}
.highlight-after-tenbrend-upgrate {
  background-color: #86ccf8;
  color: #303133;
  padding: 2px 4px;
  border-radius: 3px;
  font-weight: bold;
}
.highlight-after-tenbrend-same {
  background-color: #ccc;
  color: #303133;
  padding: 2px 4px;
  border-radius: 3px;
  font-weight: bold;
}

.arrow {
  margin: 0 5px;
  color: black;
  font-weight: bold;
}
.file-link a {
  text-decoration: none;
  cursor: pointer;
}

.file-link a:hover {
  text-decoration: underline;
}
.file-link {
  float: right; /* 让文件名靠右 */
  color: #409eff; /* 让其变成蓝色超链接 */
}
</style>
